        case 'production':
            return (
                dataFetched.production === true &&
                dataFetched.fabric === true
            );


        case 'suppliers':
            return (
                dataFetched.suppliers === true &&
                dataFetched.purchaseOrders === true
            );


        case 'notes':
            return dataFetched.notes === true;


        case 'investment':
            return (
                dataFetched.investorsAndBanks === true
            );


        default:
            return false;
    }
};


