                if (pageName === 'supplier') dataPromises.push(fetchSupplierData(userId));
                if (pageName === 'retur') dataPromises.push(fetchTransactionAndReturnData(userId));
                break;
            
            case 'gudang-kain':
                dataPromises.push(fetchProductionData(userId));
                break;
            case 'laporan-transaksi':
case 'laporan-keuangan': {
    // Laporan harus pakai data mentah terbaru, bukan summary lama.
    // Summary lama bisa masih menyimpan transaksi yang sudah dihapus.
    dataPromises.push(fetchTransactionAndReturnData(userId, false, null, null, true));
    dataPromises.push(fetchKeuanganData());
    break;
}
            case 'keuangan':
                dataPromises.push(fetchKeuanganData());
                break;
            case 'investasi':
      await fetchInvestorsAndBanksData(userId);
      break;
    
    case 'pengaturan':
      // Kita panggil fungsi ini karena data Bank ada di dalamnya
      await fetchInvestorsAndBanksData(userId); 
      break;
            
            // --- PENAMBAHAN CASE BARU DI SINI ---
            case 'panduan-baru':
case 'roas-calculator':
    break;

case 'roas-dashboard':
    dataPromises.push(fetchAllProductData(userId));
    dataPromises.push(fetchTransactionAndReturnData(userId));
    dataPromises.push(fetchKeuanganData());
    break;
}
        if (dataPromises.length > 0) {
            await Promise.all(dataPromises);
        }

        if (pageName === 'dashboard') {
            nextTick(renderCharts);
        }

        } catch (error) {
        console.error(
            `Failed to load data for page ${pageName}:`,
            error
        );
    } finally {
    pagesCurrentlyLoading.delete(pageName);

    // Sesudah halaman menampilkan data IndexedDB,
    // hidupkan network dan periksa satu dokumen versi.
    if (shouldFinishIndexedDbStartup) {
        await finishIndexedDbStartup(userId);
    }
}
};

