const parsePercentageInput = (value) => {
    if (typeof value !== 'string') return value;
    const cleaned = value.replace(',', '.').replace(/[^0-9.]/g, '');
    return parseFloat(cleaned) || 0;
};

function toExportDate(value) {
    if (!value) return null;

    if (value instanceof Date) {
        return isNaN(value.getTime()) ? null : value;
    }

    if (value?.toDate && typeof value.toDate === 'function') {
        const date = value.toDate();
        return isNaN(date.getTime()) ? null : date;
    }

    if (value?.seconds) {
        const date = new Date(value.seconds * 1000);
        return isNaN(date.getTime()) ? null : date;
    }

    const date = new Date(value);
    return isNaN(date.getTime()) ? null : date;
}

function formatExportDate(value, withTime = true) {
    const date = toExportDate(value);
    if (!date) return '';

    const pad = (num) => String(num).padStart(2, '0');

    const year = date.getFullYear();
    const month = pad(date.getMonth() + 1);
    const day = pad(date.getDate());
    const hour = pad(date.getHours());
    const minute = pad(date.getMinutes());

    if (!withTime) {
        return `${year}-${month}-${day}`;
    }

    return `${year}-${month}-${day} ${hour}:${minute}`;
}

function getAdminExportDateRange(
    exportFilter = 'all_time',
    exportStartDate = '',
    exportEndDate = '',
    exportStartMonth = new Date().getMonth() + 1,
    exportEndMonth = new Date().getMonth() + 1,
    exportStartYear = new Date().getFullYear(),
    exportEndYear = new Date().getFullYear()
) {
    const now = new Date();

    let start = null;
    let end = null;
    let label = 'Semua Data';

    const startOfDay = (date) => new Date(date.getFullYear(), date.getMonth(), date.getDate(), 0, 0, 0, 0);
    const endOfDay = (date) => new Date(date.getFullYear(), date.getMonth(), date.getDate(), 23, 59, 59, 999);

    if (exportFilter === 'today') {
        start = startOfDay(now);
        end = endOfDay(now);
        label = 'Hari Ini';
    }

    if (exportFilter === 'last_7_days') {
        start = startOfDay(new Date(now.getFullYear(), now.getMonth(), now.getDate() - 6));
        end = endOfDay(now);
        label = '7 Hari Terakhir';
    }

    if (exportFilter === 'last_30_days') {
        start = startOfDay(new Date(now.getFullYear(), now.getMonth(), now.getDate() - 29));
        end = endOfDay(now);
        label = '30 Hari Terakhir';
    }

    if (exportFilter === 'this_year') {
        start = new Date(now.getFullYear(), 0, 1, 0, 0, 0, 0);
        end = new Date(now.getFullYear(), 11, 31, 23, 59, 59, 999);
        label = `Tahun Ini ${now.getFullYear()}`;
    }

    if (exportFilter === 'by_date_range') {
        if (!exportStartDate || !exportEndDate) {
            throw new Error('Tanggal awal dan tanggal akhir export wajib diisi.');
        }

        start = startOfDay(new Date(exportStartDate));
        end = endOfDay(new Date(exportEndDate));
        label = `${formatExportDate(start, false)} s/d ${formatExportDate(end, false)}`;
    }

    if (exportFilter === 'by_month_range') {
        start = new Date(Number(exportStartYear), Number(exportStartMonth) - 1, 1, 0, 0, 0, 0);
        end = new Date(Number(exportEndYear), Number(exportEndMonth), 0, 23, 59, 59, 999);
        label = `${String(exportStartMonth).padStart(2, '0')}-${exportStartYear} s/d ${String(exportEndMonth).padStart(2, '0')}-${exportEndYear}`;
    }

    if (exportFilter === 'by_year_range') {
        start = new Date(Number(exportStartYear), 0, 1, 0, 0, 0, 0);
        end = new Date(Number(exportEndYear), 11, 31, 23, 59, 59, 999);
        label = `${exportStartYear} s/d ${exportEndYear}`;
    }

    return {
        filter: exportFilter,
        start,
        end,
        label,
        isAllTime: exportFilter === 'all_time'
    };
}

function isInsideAdminExportRange(value, range) {
    if (range.isAllTime) return true;

    const date = toExportDate(value);
    if (!date) return false;

    return date >= range.start && date <= range.end;
}


function safeSheetName(name) {
    let cleanName = String(name || 'Sheet');

    const forbiddenChars = [':', '\\', '/', '?', '*', '[', ']'];

    forbiddenChars.forEach(char => {
        cleanName = cleanName.split(char).join(' ');
    });

    cleanName = cleanName.trim().substring(0, 31);

    return cleanName || 'Sheet';
}

function appendExportSheet(workbook, sheetName, rows, columnWidths = []) {
    const safeRows = rows && rows.length > 0
        ? rows
        : [{ Keterangan: 'Tidak ada data pada periode export ini.' }];

    const worksheet = XLSX.utils.json_to_sheet(safeRows, { cellDates: true });

    if (worksheet['!ref']) {
        worksheet['!autofilter'] = { ref: worksheet['!ref'] };
    }

    worksheet['!cols'] = columnWidths.length > 0
        ? columnWidths.map(width => ({ wch: width }))
        : Object.keys(safeRows[0] || {}).map(key => ({ wch: Math.min(Math.max(key.length + 6, 16), 40) }));

    XLSX.utils.book_append_sheet(workbook, worksheet, safeSheetName(sheetName));
}

function snapshotToRows(snapshot) {
    return snapshot.docs.map(docSnap => ({
        docId: docSnap.id,
        id: docSnap.id,
        ...docSnap.data()
    }));
}

function isActiveExportRecord(item) {
    if (!item) return false;

    const status = String(item.status || item.statusData || item.statusProses || '').toLowerCase();

    if (item.isDeleted === true) return false;
    if (item.deleted === true) return false;
    if (item.archived === true) return false;
    if (item.deletedAt) return false;
    if (status === 'deleted') return false;
    if (status === 'dihapus') return false;
    if (status === 'arsip') return false;
    if (status === 'archived') return false;

    return true;
}



function isValidNumberForExport(value) {
    return value !== null && value !== undefined && value !== '' && !isNaN(Number(value));
}

function exportNumber(value) {
    return isValidNumberForExport(value) ? Number(value) : 0;
}

function getActiveArray(items) {
    return (items || []).filter(isActiveExportRecord);
}

async function getDocsByProductIds(
    collectionName,
    productIds,
    ownerUserId = null,
    readFromServer = true
) {
    const results = [];

    const cleanIds = [
        ...new Set(
            (productIds || []).filter(Boolean)
        )
    ];

    const readDocuments =
        readFromServer
            ? getDocsFromServer
            : getDocs;

    for (
        let index = 0;
        index < cleanIds.length;
        index += 10
    ) {
        const chunk = cleanIds.slice(
            index,
            index + 10
        );

        if (chunk.length === 0) continue;

        const snapshot = await readDocuments(
            query(
                collection(
                    db,
                    collectionName
                ),
                where(
                    "product_id",
                    "in",
                    chunk
                )
            )
        );

        const rows =
            snapshotToRows(snapshot).filter(row => {
                if (!ownerUserId) return true;

                // Data harga lama belum tentu mempunyai userId.
                if (!row.userId) return true;

                return row.userId === ownerUserId;
            });

        results.push(...rows);
    }

    return results;
}

function dedupeRowsByDocId(rows) {
    const map = new Map();

    (rows || []).forEach(row => {
        const key = row.docId || row.id;
        if (!key) return;
        map.set(key, row);
    });

    return [...map.values()];
}



function buildMarketplaceRowsForExport(marketplaces = [], sourceLabel = 'Data aplikasi yang sedang tampil') {
    return JSON.parse(JSON.stringify(marketplaces || [])).map((mp, index) => {
        const programs = Array.isArray(mp.programs)
            ? mp.programs
            : (Array.isArray(mp.program) ? mp.program : []);

        const programText = programs.length > 0
            ? programs.map(program => {
                const name = program.name || program.nama || program.programName || 'Program';
                const type = program.type || program.jenis || program.satuan || program.unit || '%';
                const value = program.rate ?? program.value ?? program.amount ?? program.nominal ?? program.biaya ?? '';

                if (String(type).toLowerCase().includes('rp')) {
                    return `${name} (Rp ${new Intl.NumberFormat('id-ID').format(Number(value) || 0)})`;
                }

                return `${name} (${value}%)`;
            }).join('; ')
            : '';

        return {
            'No': index + 1,
            'Sumber Data': sourceLabel,
            'ID Channel': mp.id || '',
            'Nama Channel': mp.name || mp.nama || '',
            'Biaya Admin (%)': mp.adm ?? mp.admin ?? 0,
            'Biaya Layanan G Xtra (%)': mp.layanan ?? mp.serviceFee ?? 0,
            'Biaya Per Pesanan': mp.perPesanan ?? mp.biayaPerPesanan ?? 0,
            'Jumlah Program': programs.length,
            'Program Tambahan': programText
        };
    });
}

function exportMarketplaceYangTampil() {
    const marketplaces = state.settings.marketplaces || [];

    if (marketplaces.length === 0) {
        alert('Tidak ada data marketplace untuk diexport.');
