const getExpenseTypeByCategory = (kategori) => {
    const category = (state.settings.categories || []).find(cat => cat.name === kategori);

    if (category?.type) {
        return category.type;
    }

    const nama = (kategori || '').toLowerCase();

    const productionKeywords = [
        'kain',
        'jahit',
        'maklun',
        'supplier',
        'produksi',
        'bahan',
        'aksesoris',
        'resleting',
        'kancing',
        'label',
        'hangtag',
        'bordir',
        'payet',
        'obras',
        'kerugian stok'
    ];

    return productionKeywords.some(keyword => nama.includes(keyword))
        ? 'produksi'
        : 'operasional';
};

// --- LOGIKA FILTER YANG SUDAH DIPERBAIKI ---
const filteredMassPriceVariants = computed(() => {
    // 1. Ambil data source
    let variants = uiState.massUpdateVariants || [];

    // 2. Filter berdasarkan Ukuran (DIGANTI JADI EXACT MATCH)
    if (uiState.massPriceFilterUkuran) {
        const keyword = uiState.massPriceFilterUkuran.toString().toLowerCase().trim();
        
        variants = variants.filter(v => {
            const val = String(v.varian || '').toLowerCase();
            // PERUBAHAN PENTING DI SINI:
            // Gunakan '===' (Sama Persis). 
            // Jadi kalau ketik "l", hanya "l" yang muncul. "xl" tidak akan muncul.
            return val === keyword; 
        });
    }

    // 3. Filter berdasarkan Warna (TETAP PAKAI INCLUDES AGAR FLEKSIBEL)
    if (uiState.massPriceFilterWarna) {
        const keyword = uiState.massPriceFilterWarna.toString().toLowerCase().trim();
        
        variants = variants.filter(v => {
            const val = String(v.warna || '').toLowerCase();
            // Warna tetap pakai 'includes' supaya ketik "merah" bisa ketemu "merah maroon"
            return val.includes(keyword);
        });
    }

    return variants;
});

const isSubscriptionActive = computed(() => {
    const now = currentTime.value; // Gunakan waktu reaktif kita

    if (!userProfile.data) {
        return false;
    }

    const status = userProfile.data.subscriptionStatus;

    // Cek jika masa trial aktif
    if (status === 'trial' && userProfile.data.trialEndDate) {
        const trialEndDate = new Date(userProfile.data.trialEndDate.seconds * 1000);
        if (trialEndDate > now) return true;
    }

    // Cek jika masa langganan berbayar aktif
    if (status === 'active' && userProfile.data.subscriptionEndDate) {
        // Cek jika subscriptionEndDate adalah Firestore Timestamp atau JS Date
        const endDateValue = userProfile.data.subscriptionEndDate.seconds 
            ? userProfile.data.subscriptionEndDate.seconds * 1000 
            : new Date(userProfile.data.subscriptionEndDate).getTime();

        if (endDateValue > now) return true;
    }

    return false;
});

let unsubscribeSummary = null; // Variabel untuk menyimpan listener

const fetchSummaryData = (userId) => {
    if (unsubscribeSummary) {
        unsubscribeSummary(); // Hentikan listener lama jika ada
    }

    if (!userId) {
        state.summaryData = {};
        return;
    }

    const summaryRef = doc(db, "user_summaries", userId);
    // Gunakan onSnapshot untuk 'mendengarkan' perubahan secara real-time
    unsubscribeSummary = onSnapshot(summaryRef, (docSnap) => {
        if (docSnap.exists()) {
            state.summaryData = docSnap.data();
        } else {
            console.log("Dokumen ringkasan belum ada, akan dibuat otomatis oleh Cloud Function.");
            state.summaryData = {};
        }
    }, (error) => {
        console.error("Gagal mendengarkan summary data:", error);
    });
};
