        return;
    }

    uiState.isExportingUserData = true;

    try {
        const workbook = XLSX.utils.book_new();

        const [
            userSettingsSnap,
            productsSnap,
            productPricesSnap,
            bankAccountsSnap,
            keuanganSnap,
            transactionsSnap,
            returnsSnap,
            productionSnap,
            suppliersSnap,
            purchaseOrdersSnap,
            investorsSnap,
            investorPaymentsSnap,
            categoriesSnap
        ] = await Promise.all([
    getDocFromServer(doc(db, "settings", userId)),
    getDocsFromServer(query(collection(db, "products"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "product_prices"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "bank_accounts"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "keuangan"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "transactions"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "returns"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "production_batches"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "suppliers"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "purchase_orders"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "investors"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "investor_payments"), where("userId", "==", userId))),
    getDocsFromServer(query(collection(db, "categories"), where("userId", "==", userId)))
]);

        const userSettings = userSettingsSnap.exists()
            ? userSettingsSnap.data()
            : { marketplaces: [], modelProduk: [], categories: [], inflowCategories: [] };

        const productsRawAll = getActiveArray(snapshotToRows(productsSnap));
const bankAccountsRaw = getActiveArray(snapshotToRows(bankAccountsSnap));
const keuanganRaw = getActiveArray(snapshotToRows(keuanganSnap));
const transactionsRaw = getActiveArray(snapshotToRows(transactionsSnap));
const returnsRaw = getActiveArray(snapshotToRows(returnsSnap));
const productionRaw = getActiveArray(snapshotToRows(productionSnap));
const suppliersRaw = getActiveArray(snapshotToRows(suppliersSnap));
const purchaseOrdersRaw = getActiveArray(snapshotToRows(purchaseOrdersSnap));
const investorsRaw = getActiveArray(snapshotToRows(investorsSnap));
const investorPaymentsRaw = getActiveArray(snapshotToRows(investorPaymentsSnap));
const categoriesRaw = getActiveArray(snapshotToRows(categoriesSnap));

const activeMarketplaces = getActiveArray(userSettings.marketplaces || []);
const activeModels = getActiveArray(userSettings.modelProduk || []);
const activeCategories = getActiveArray(userSettings.categories || []);
const activeInflowCategories = getActiveArray(userSettings.inflowCategories || []);

const activeMarketplaceIds = new Set(activeMarketplaces.map(channel => channel.id).filter(Boolean));
const activeModelIds = new Set(activeModels.map(model => model.id).filter(Boolean));

const productsRaw = productsRawAll.filter(product => {
    if (!isActiveExportRecord(product)) return false;

    // Kalau produk punya model_id, pastikan modelnya masih aktif.
    // Kalau model_id kosong, tetap export karena bisa jadi data lama.
    if (product.model_id && activeModelIds.size > 0 && !activeModelIds.has(product.model_id)) {
        return false;
    }

    return true;
});

const activeProductIds = new Set();
const activeProductSkus = new Set();

productsRaw.forEach(product => {
    if (product.docId) activeProductIds.add(product.docId);
    if (product.id) activeProductIds.add(product.id);
    if (product.sku) activeProductSkus.add(product.sku);
});

// Ambil harga dari 2 jalur:
// 1. by userId
// 2. by product_id, untuk data lama yang mungkin belum punya userId
const productPricesByUser = getActiveArray(snapshotToRows(productPricesSnap));
const productPricesByProduct = await getDocsByProductIds("product_prices", [...activeProductIds], userId);
const productPricesRaw = dedupeRowsByDocId([
    ...productPricesByUser,
    ...productPricesByProduct
]).filter(price => {
    if (!isActiveExportRecord(price)) return false;

    const productId = price.product_id || '';
    const sku = price.product_sku || '';
    const marketplaceId = price.marketplace_id || '';

    const productStillExists =
        activeProductIds.has(productId) ||
        activeProductSkus.has(sku);

    const marketplaceStillExists =
    !marketplaceId ||
    activeMarketplaceIds.size === 0 ||
    activeMarketplaceIds.has(marketplaceId);

    return productStillExists && marketplaceStillExists;
});

        const marketplaceMap = {};
activeMarketplaces.forEach(channel => {
    marketplaceMap[channel.id] = channel.name;
});

const modelMap = {};
activeModels.forEach(model => {
    modelMap[model.id] = model.namaModel;
});

        const productBySku = {};
        const productById = {};

        productsRaw.forEach(product => {
            if (product.sku) productBySku[product.sku] = product;
            productById[product.docId] = product;
            if (product.id) productById[product.id] = product;
        });

        const getProductName = (sku) => {
            const product = productBySku[sku];
            return product?.product_name || product?.nama || '';
        };

        const getChannelName = (channelId, fallback = '') => {
            return marketplaceMap[channelId] || fallback || channelId || '';
        };

        // =========================
        // 00. INFO EXPORT
        // =========================
        appendExportSheet(workbook, '00 Info Export', [
            { Info: 'Nama Aplikasi', Nilai: 'Fashion OS' },
            { Info: 'Jenis Export', Nilai: 'Export Admin Developer' },
            { Info: 'Email User', Nilai: userEmail || '' },
            { Info: 'User ID', Nilai: userId },
            { Info: 'Filter Export', Nilai: exportRange.label },
            { Info: 'Tanggal Mulai Filter', Nilai: exportRange.start ? formatExportDate(exportRange.start) : 'Semua Data' },
            { Info: 'Tanggal Akhir Filter', Nilai: exportRange.end ? formatExportDate(exportRange.end) : 'Semua Data' },
            { Info: 'Dibuat Pada', Nilai: formatExportDate(new Date()) },
            { Info: 'Catatan', Nilai: 'Data transaksi, retur, keuangan, produksi, purchase order, dan pembayaran investor mengikuti filter waktu. Data master tetap lengkap agar referensi SKU, produk, channel, model, dan supplier tidak hilang.' }
        ], [24, 80]);

const marketplaceSource = currentUser.value?.uid === userId
    ? JSON.parse(JSON.stringify(state.settings.marketplaces || []))
    : JSON.parse(JSON.stringify(userSettings.marketplaces || []));

const marketplaceSourceLabel = currentUser.value?.uid === userId
    ? 'state.settings.marketplaces - data yang tampil di aplikasi'
    : `settings/${userId} - data Firestore`;

const marketplaceRows = buildMarketplaceRowsForExport(
    marketplaceSource,
    marketplaceSourceLabel
);

appendExportSheet(workbook, '01 Marketplace', marketplaceRows, [8, 45, 30, 34, 18, 24, 20, 18, 60]);
        // =========================
        // 02. MODEL PRODUK
        // =========================
        const modelRows = activeModels.map(model => ({
    'ID Model': model.id || '',
    'Nama Model': model.namaModel || '',
    'Warna Default': model.warna || '',
    'Ukuran Default': model.ukuran || '',
    'Yard Per Model': exportNumber(model.yardPerModel),
    'Harga Maklun': exportNumber(model.hargaMaklun),
    'Harga Jahit': exportNumber(model.hargaJahit)
}));

        appendExportSheet(workbook, '02 Model Produk', modelRows, [24, 30, 22, 18, 18, 18, 18]);

        // =========================
        // 03. KATEGORI BIAYA
        // =========================
        const settingCategoryRows = [
    ...activeCategories.map(category => ({
        'Sumber': 'settings.categories',
        'ID Kategori': category.id || '',
        'Nama Kategori': category.name || '',
        'Tipe': category.type || '',
        'Deskripsi': category.description || ''
    })),
    ...activeInflowCategories.map(category => ({
        'Sumber': 'settings.inflowCategories',
        'ID Kategori': category.id || '',
        'Nama Kategori': category.name || '',
        'Tipe': 'pemasukan',
        'Deskripsi': category.description || ''
    })),
    ...categoriesRaw.map(category => ({
        'Sumber': 'collection.categories',
        'ID Kategori': category.docId || '',
        'Nama Kategori': category.name || category.nama || '',
        'Tipe': category.type || '',
        'Deskripsi': category.description || ''
    }))
];

        appendExportSheet(workbook, '03 Kategori', settingCategoryRows, [28, 24, 32, 18, 50]);

        // =========================
        // 04. PRODUK MASTER
        // =========================
        const productRows = productsRaw.map(product => ({
            'ID Produk': product.docId || '',
            'SKU': product.sku || '',
            'Nama Produk': product.product_name || product.nama || '',
            'ID Model': product.model_id || '',
            'Nama Model': modelMap[product.model_id] || '',
            'Warna': product.color || product.warna || '',
            'Ukuran': product.variant || product.varian || '',
            'Stok Fisik': exportNumber(product.physical_stock ?? product.stokFisik),
            'HPP': exportNumber(product.hpp),
            'Harga Beli Supplier': exportNumber(product.hargaBeli),
            'Tanggal Dibuat': formatExportDate(product.createdAt),
            'Tanggal Update': formatExportDate(product.updatedAt)
        }));

        appendExportSheet(workbook, '04 Produk Master', productRows, [28, 24, 36, 24, 28, 18, 14, 14, 16, 18, 22, 22]);

        // =========================
        // 05. HARGA JUAL
        // =========================
        const priceRows = productPricesRaw.map(price => {
            const product = productById[price.product_id] || productBySku[price.product_sku] || {};

            return {
                'ID Harga': price.docId || '',
