            { Metrik: 'Total Nilai Retur', Nilai: totalNilaiRetur },
            { Metrik: 'Total Pemasukan Lain', Nilai: totalKeuanganMasuk },
            { Metrik: 'Total Pengeluaran / Biaya', Nilai: totalKeuanganKeluar },
