async function submitAddProduct() {
    const form = uiState.modalData;
    if (!form.sku || !form.nama || !form.modelId || !form.warna || !form.varian) {
        alert('SKU, Nama, Model produk, Warna, dan Varian wajib diisi.');
        return;
    }

    const skuFormatted = form.sku.toUpperCase().replace(/\s+/g, '-');
    const userId = currentUser.value.uid;

    try {
        const productsCollection = collection(db, "products");
        const q = query(productsCollection, where("sku", "==", skuFormatted), where("userId", "==", userId));
        const querySnapshot = await getDocs(q);

        if (!querySnapshot.empty) {
            throw new Error(`Produk dengan SKU "${skuFormatted}" sudah terdaftar untuk akun Anda.`);
        }

        const newProductRef = doc(collection(db, "products"));

        const productData = {
            id: newProductRef.id,
            product_name: form.nama,
            model_id: form.modelId,
            color: form.warna || '',
            variant: form.varian || '',
            physical_stock: 0,
            hpp: 0,
            userId: userId,
            sku: skuFormatted
        };

        const batch = writeBatch(db);
        batch.set(newProductRef, productData);

        state.settings.marketplaces.forEach(channel => {
            const priceDocId = `${newProductRef.id}-${channel.id}`;
            const priceRef = doc(db, "product_prices", priceDocId);
            batch.set(priceRef, {
                product_id: newProductRef.id,
                product_sku: skuFormatted,
                marketplace_id: channel.id,
                price: 0,
                userId: userId
            });
        });

        await batch.commit();

        // --- PERBAIKAN DIMULAI DI SINI ---

        // Buat objek produk baru untuk ditambahkan ke state lokal
        const newProductObject = {
            docId: newProductRef.id,
            sku: productData.sku,
            nama: productData.product_name,
            model_id: productData.model_id,
            warna: productData.color,
            varian: productData.variant,
            stokFisik: productData.physical_stock,
            hpp: productData.hpp,
            hargaJual: {},
            stokAlokasi: {},
            userId: productData.userId
        };

        // 1. Tambahkan ke state utama (untuk halaman HPP, Promosi, dll)
        state.produk.push(newProductObject);
        
        // 2. Tambahkan juga ke state tampilan inventaris agar UI langsung update
        state.inventoryPaginated.push(newProductObject);

        // --- AKHIR PERBAIKAN ---

        alert(`Produk "${form.nama}" berhasil ditambahkan!`);
        hideModal();

    } catch (error) {
        console.error('Error menyimpan produk:', error);
        alert(`Gagal menyimpan produk: ${error.message}`);
    }
}


const laporanKeuanganData = computed(() => {
    const year = uiState.laporanKeuanganTahun;
    
    const months = [];

    const dataTransaksiMentah = state.transaksi || [];
    const dataKeuanganMentah = state.keuangan || [];

    for (let i = 1; i <= 12; i++) {
        
        const monthName = new Date(year, i - 1, 1).toLocaleString('id-ID', { month: 'long' });

        let data = null;

        const trxBulanIni = dataTransaksiMentah.filter(t => {
            const d = new Date(t.tanggal);
            return d.getFullYear() === year && (d.getMonth() + 1) === i && t.statusPencairan === 'Sudah Cair';
        });

        const biayaBulanIni = dataKeuanganMentah.filter(k => {
    const d = k.tanggal?.toDate
        ? k.tanggal.toDate()
        : (k.tanggal instanceof Date ? k.tanggal : new Date(k.tanggal));

    return d.getFullYear() === year &&
        (d.getMonth() + 1) === i &&
        (k.jenis === 'pengeluaran' || k.jenis === 'biaya');
});

        const biayaProduksi = biayaBulanIni
            .filter(k => (k.tipeBiaya || getExpenseTypeByCategory(k.kategori)) === 'produksi')
            .reduce((sum, k) => sum + (k.jumlah || 0), 0);

        const biayaOperasional = biayaBulanIni
            .filter(k => (k.tipeBiaya || getExpenseTypeByCategory(k.kategori)) !== 'produksi')
            .reduce((sum, k) => sum + (k.jumlah || 0), 0);

        if (!data) {
            const omsetKotor = trxBulanIni.reduce((sum, t) => sum + (t.subtotal || 0), 0);
            const diskon = trxBulanIni.reduce((sum, t) => sum + (t.diskon?.totalDiscount || 0), 0);
            const omsetBersih = omsetKotor - diskon;
            const hppTerjual = trxBulanIni.reduce((sum, t) => {
                return sum + (t.items || []).reduce((s, item) => s + (item.hpp || 0) * item.qty, 0);
            }, 0);
            const biayaTransaksi = trxBulanIni.reduce((sum, t) => sum + (t.biaya?.total || 0), 0);
            const labaKotor = omsetBersih - hppTerjual;

            data = { omsetKotor, omsetBersih, labaKotor, biayaTransaksi };
        }

        const labaBersihFinal =
    (data.labaKotor || 0) -
    (data.biayaTransaksi || 0) -
    biayaOperasional;

        months.push({
            monthName,
            omsetKotor: data.omsetKotor || 0,
            omsetBersih: data.omsetBersih || 0,
            labaKotor: data.labaKotor || 0,
            labaBersih: labaBersihFinal,
            totalBiayaProduksi: biayaProduksi,
            totalBiayaOperasional: biayaOperasional,
            totalBiayaTransaksi: data.biayaTransaksi || 0,
        });
    }

    const yearlyTotals = {
        omsetKotor: months.reduce((sum, m) => sum + m.omsetKotor, 0),
        omsetBersih: months.reduce((sum, m) => sum + m.omsetBersih, 0),
        labaKotor: months.reduce((sum, m) => sum + m.labaKotor, 0),
        labaBersih: months.reduce((sum, m) => sum + m.labaBersih, 0),
        totalBiayaProduksi: months.reduce((sum, m) => sum + m.totalBiayaProduksi, 0),
        totalBiayaOperasional: months.reduce((sum, m) => sum + m.totalBiayaOperasional, 0),
        totalBiayaTransaksi: months.reduce((sum, m) => sum + m.totalBiayaTransaksi, 0),
    };

    return { months, yearlyTotals };
});

const laporanTransaksiData = computed(() => {
    const year = uiState.laporanTransaksiTahun;
    
    const months = [];
    const dataTransaksiMentah = state.transaksi || [];

    for (let i = 1; i <= 12; i++) {
        
        const monthName = new Date(year, i - 1, 1).toLocaleString('id-ID', { month: 'long' });
        
        let data = null;

        // Jika data dari server kosong, hitung manual secara real-time di lokal
        if (!data) {
            const trxBulanIni = dataTransaksiMentah.filter(t => {
                const d = new Date(t.tanggal);
                return d.getFullYear() === year && (d.getMonth() + 1) === i && t.statusPencairan === 'Sudah Cair';
            });

            const totalQty = trxBulanIni.reduce((sum, t) => sum + (t.items || []).reduce((s, item) => s + item.qty, 0), 0);
            const omsetKotor = trxBulanIni.reduce((sum, t) => sum + (t.subtotal || 0), 0);
            const totalDiskon = trxBulanIni.reduce((sum, t) => sum + (t.diskon?.totalDiscount || 0), 0);
            const omsetBersih = omsetKotor - totalDiskon;
            const hppTerjual = trxBulanIni.reduce((sum, t) => sum + (t.items || []).reduce((s, item) => s + (item.hpp || 0) * item.qty, 0), 0);
            const biayaTransaksi = trxBulanIni.reduce((sum, t) => sum + (t.biaya?.total || 0), 0);
            const labaKotor = omsetBersih - hppTerjual;

            data = { totalQty, omsetKotor, totalDiskon, nilaiRetur: 0, omsetBersih, hppTerjual, biayaTransaksi, labaKotor };
        }

        months.push({
            monthName: monthName,
            totalQty: data.totalQty || 0,
            omsetKotor: data.omsetKotor || 0,
            totalDiskon: data.totalDiskon || 0,
            totalNilaiRetur: data.nilaiRetur || 0,
            omsetBersih: data.omsetBersih || 0,
            totalHppTerjual: data.hppTerjual || 0,
            totalBiayaTransaksi: data.biayaTransaksi || 0,
            labaKotor: data.labaKotor || 0,
        });
    }
    
    const yearlyTotals = {
        totalQty: months.reduce((sum, m) => sum + m.totalQty, 0),
        omsetKotor: months.reduce((sum, m) => sum + m.omsetKotor, 0),
        totalDiskon: months.reduce((sum, m) => sum + m.totalDiskon, 0),
        totalNilaiRetur: months.reduce((sum, m) => sum + m.totalNilaiRetur, 0),
        omsetBersih: months.reduce((sum, m) => sum + m.omsetBersih, 0),
        totalHppTerjual: months.reduce((sum, m) => sum + m.totalHppTerjual, 0),
        totalBiayaTransaksi: months.reduce((sum, m) => sum + m.totalBiayaTransaksi, 0),
        labaKotor: months.reduce((sum, m) => sum + m.labaKotor, 0),
    };

    return { months, yearlyTotals };
});

const roasResults = computed(() => {
    const { hargaJual, modalProduk, biayaPacking, biayaAdminMarketplace } = uiState.roasCalculator;

    if (!hargaJual || hargaJual <= 0) {
        return { error: "Harga Jual harus diisi." };
    }

    // --- PERBAIKAN RUMUS DI SINI ---
    // Biaya Admin sekarang ditambahkan langsung sebagai angka Rupiah
    const totalBiayaProduk = (modalProduk || 0) + (biayaPacking || 0) + (biayaAdminMarketplace || 0);
    const profitKotor = hargaJual - totalBiayaProduk;

    if (profitKotor <= 0) {
        return {
            totalBiayaProduk,
            profitKotor,
            error: "Harga Jual lebih rendah dari total biaya, tidak mungkin profit."
        };
    }

    const breakEvenROAS = hargaJual / profitKotor;

    const targets = [10, 15, 20, 25, 30].map(marginPercent => {
        const targetProfit = hargaJual * (marginPercent / 100);
        const maxBiayaIklanPerOrder = profitKotor - targetProfit;
        if (maxBiayaIklanPerOrder <= 0) {
            return { margin: marginPercent, roas: Infinity };
        }
        return {
            margin: marginPercent,
            roas: hargaJual / maxBiayaIklanPerOrder
        };
    });

    return {
        totalBiayaProduk,
        profitKotor,
        profitMargin: (profitKotor / hargaJual) * 100,
        breakEvenROAS,
        targets,
    };
});

const roasSimulationResults = computed(() => {
    const results = roasResults.value;
    const { estimasiBiayaIklan, hargaJual, customRoasTarget } = uiState.roasCalculator;

    if (!hargaJual || hargaJual <= 0 || !estimasiBiayaIklan || estimasiBiayaIklan <= 0 || results.error) {
        // Jika input belum lengkap, kembalikan array kosong
        return [
            { scenario: 'Skenario Impas (BEP)', targetRoas: 'N/A', estimasiOrder: 0, estimasiOmset: 0, estimasiLabaBersih: 0 },
            { scenario: 'Skenario Target Profit 20%', targetRoas: 'N/A', estimasiOrder: 0, estimasiOmset: 0, estimasiLabaBersih: 0 },
            { scenario: 'Skenario Kustom', targetRoas: customRoasTarget || 0, estimasiOrder: 0, estimasiOmset: 0, estimasiLabaBersih: 0 },
        ];
    }

    const calculateScenario = (scenarioName, roasTarget) => {
        if (!isFinite(roasTarget) || roasTarget <= 0) {
            return { scenario: scenarioName, targetRoas: 'N/A', estimasiOrder: 0, estimasiOmset: 0, estimasiLabaBersih: 0 };
        }
        
        // Rumus inti yang sudah benar
        const estimasiOmset = estimasiBiayaIklan * roasTarget;
        const estimasiOrder = hargaJual > 0 ? estimasiOmset / hargaJual : 0;
        const estimasiProfitKotor = estimasiOrder * results.profitKotor;
        const estimasiLabaBersih = estimasiProfitKotor - estimasiBiayaIklan;

        return {
            scenario: scenarioName,
            targetRoas: roasTarget,
            estimasiOrder,
            estimasiOmset,
            estimasiLabaBersih,
        };
    };

    // Cari target ROAS untuk 20% dari hasil perhitungan yang sudah benar
    const targetRoas20Percent = results.targets.find(t => t.margin === 20)?.roas || 0;

    return [
        calculateScenario('Skenario Impas (BEP)', results.breakEvenROAS),
        calculateScenario('Skenario Target Profit 20%', targetRoas20Percent),
        calculateScenario('Skenario Kustom', customRoasTarget || 0),
    ];
});

async function addSupplier() {
    if (!currentUser.value) return alert("Anda harus login.");
    const form = uiState.modalData;
    if (!form.name) return alert("Nama supplier tidak boleh kosong.");
    
    const dataToSave = { ...form, userId: currentUser.value.uid, products: [] };
    
    try {
        const docRef = await addDoc(collection(db, "suppliers"), dataToSave);
        state.suppliers.push({ id: docRef.id, ...dataToSave });
        hideModal();
        alert('Supplier baru berhasil ditambahkan!');
    } catch (error) {
        console.error("Gagal menambah supplier:", error);
        alert("Gagal menambah supplier. Silakan coba lagi.");
    }
}

async function updateSupplier() {
    if (!currentUser.value) return alert("Anda harus login.");
    const form = uiState.modalData;
    
    try {
        const supplierRef = doc(db, "suppliers", form.id);
        await updateDoc(supplierRef, { name: form.name, contact: form.contact });
        
        const index = state.suppliers.findIndex(s => s.id === form.id);
        if (index !== -1) {
            state.suppliers[index].name = form.name;
            state.suppliers[index].contact = form.contact;
        }
        
        hideModal();
        alert('Data supplier berhasil diperbarui!');
    } catch (error) {
        console.error("Gagal memperbarui supplier:", error);
        alert("Gagal memperbarui supplier. Silakan coba lagi.");
    }
}

async function deleteSupplier(supplierId) {
    if (!confirm("Anda yakin ingin menghapus supplier ini? Semua data produknya juga akan terhapus.")) {
        return;
    }
    
    try {
        await deleteDoc(doc(db, "suppliers", supplierId));
