function filterDataByDate(data, filterType, startDateStr, endDateStr, startMonth, startYear, endMonth, endYear) {
    if (!data) return [];
    
    const today = new Date();
    today.setHours(0, 0, 0, 0); 

    return data.filter(item => {
        if (!item.tanggal) return false;
        
        // KRITIS: Pastikan konversi ke Date dan waktu di-reset
        const itemDate = item.tanggal?.seconds 
    ? new Date(item.tanggal.seconds * 1000) 
    : new Date(item.tanggal);
        itemDate.setHours(0, 0, 0, 0); 

        switch (filterType) {
            case 'today': {
    const t = new Date(); // Ambil waktu detik ini
    return itemDate.getDate() === t.getDate() &&
           itemDate.getMonth() === t.getMonth() &&
           itemDate.getFullYear() === t.getFullYear();
}

            case 'last_7_days': {
                const sevenDaysAgo = new Date(today);
                sevenDaysAgo.setDate(today.getDate() - 7);
                return itemDate >= sevenDaysAgo;
            }
            case 'last_30_days': {
                const thirtyDaysAgo = new Date(today);
                thirtyDaysAgo.setDate(today.getDate() - 30);
                return itemDate >= thirtyDaysAgo;
            }
            case 'this_year':
                return itemDate.getFullYear() === today.getFullYear();

            case 'by_date_range': {
                if (!startDateStr || !endDateStr) return true;
                const start = new Date(startDateStr);
                const end = new Date(endDateStr);
                start.setHours(0, 0, 0, 0);
                end.setHours(23, 59, 59, 999);
                return itemDate >= start && itemDate <= end;
            }
            
            case 'by_month_range': {
                if (!startMonth || !startYear || !endMonth || !endYear) return true;
                const start = new Date(startYear, startMonth - 1, 1);
                const end = new Date(endYear, endMonth, 0); 
                end.setHours(23, 59, 59, 999);
                return itemDate >= start && itemDate <= end;
            }
            
            case 'by_year_range': {
                if (!startYear || !endYear) return true;
                const start = new Date(startYear, 0, 1);
                const end = new Date(endYear, 11, 31);
                end.setHours(23, 59, 59, 999);
                return itemDate >= start && itemDate <= end;
            }
            
            case 'all_time':
            default:
                return true;
        }
    });
}

const formatInputNumber = (value) => {
    if (value === null || value === undefined) return '';
    return new Intl.NumberFormat('id-ID').format(value);
};

const parseInputNumber = (value) => {
    if (value === null || value === undefined || value === '') return 0;
    const parsed = value.toString().replace(/[^0-9]/g, '');
    return parseInt(parsed, 10) || 0;
};


// --- COMPUTED PROPERTIES ---
const uniqueRoasModels = computed(() => {
    const modelMap = new Map();

    (state.settings.modelProduk || []).forEach(model => {
        const namaDasar = (model.namaModel || '').split(' ')[0];

        if (namaDasar && !modelMap.has(namaDasar)) {
            modelMap.set(namaDasar, {
                namaModel: namaDasar
            });
        }
    });

    return Array.from(modelMap.values()).sort((a, b) =>
        a.namaModel.localeCompare(b.namaModel)
    );
});

const roasDashboardData = computed(() => {
    let transaksi = state.transaksi || [];

    transaksi = filterDataByDate(
        transaksi,
        uiState.roasDashboard.dateFilter,
        uiState.roasDashboard.startDate,
        uiState.roasDashboard.endDate,
        uiState.roasDashboard.startMonth,
        uiState.roasDashboard.startYear,
        uiState.roasDashboard.endMonth,
        uiState.roasDashboard.endYear
    );

    if (uiState.roasDashboard.channelId !== 'all') {
        transaksi = transaksi.filter(t => 
            t.channelId === uiState.roasDashboard.channelId || 
            t.channel === uiState.roasDashboard.channelId
        );
    }
if (uiState.roasDashboard.selectedModelId !== 'all') {
    const selectedModelName = uiState.roasDashboard.selectedModelId;

    transaksi = transaksi
        .map(t => {
            const originalItems = t.items || [];

            const filteredItems = originalItems.filter(item => {
                const productData = state.produk.find(p => p.sku === item.sku);

                const modelId =
                    item.model_id ||
                    item.modelId ||
                    productData?.model_id ||
                    productData?.modelId ||
                    '';

                const modelData = state.settings.modelProduk.find(m => m.id === modelId);
                const namaDasar = (modelData?.namaModel || '').split(' ')[0];

                return namaDasar === selectedModelName;
            });

            if (filteredItems.length === 0) return null;

            const itemSubtotal = filteredItems.reduce((sum, item) => {
                return sum + ((item.hargaJual || item.price || 0) * (item.qty || 0));
            }, 0);

            const transaksiSubtotal = originalItems.reduce((sum, item) => {
                return sum + ((item.hargaJual || item.price || 0) * (item.qty || 0));
            }, 0);

            const ratio = transaksiSubtotal > 0 ? itemSubtotal / transaksiSubtotal : 1;

            return {
                ...t,
                items: filteredItems,
                total: itemSubtotal,
                subtotal: itemSubtotal,
                diskon: typeof t.diskon === 'object'
                    ? { ...t.diskon, totalDiscount: (t.diskon.totalDiscount || 0) * ratio }
                    : (t.diskon || 0) * ratio,
                biaya: {
                    ...(t.biaya || {}),
                    total: (t.biaya?.total || 0) * ratio
                }
            };
        })
        .filter(Boolean);
}
    const omset = transaksi.reduce((sum, t) => sum + (t.subtotal || t.total || 0), 0);
    const totalOrder = transaksi.length;

    const qtyTerjual = transaksi.reduce((sum, t) => {
        return sum + (t.items || []).reduce((s, item) => s + (item.qty || 0), 0);
    }, 0);

    const totalHpp = transaksi.reduce((sum, t) => {
        return sum + (t.items || []).reduce((s, item) => {
            return s + ((item.hpp || 0) * (item.qty || 0));
        }, 0);
    }, 0);


    const biayaMarketplace = transaksi.reduce((sum, t) => {
        return sum + (t.biaya?.total || 0);
    }, 0);

    const discount = transaksi.reduce((sum, t) => {
    const diskonValue = typeof t.diskon === 'object'
        ? (t.diskon.totalDiscount || 0)
        : (t.diskon || 0);

    return sum + diskonValue;
}, 0);


    const biayaIklan = parseInputNumber(uiState.roasDashboard.adSpend);
    const biayaOperasional = parseInputNumber(uiState.roasDashboard.operationalBudget);
    const pajakPersen = parseFloat(uiState.roasDashboard.taxPercent) || 0;
    const pajak = biayaIklan * (pajakPersen / 100);

    const labaKotor = omset - totalHpp;
    const labaBersih = omset - discount - totalHpp - biayaMarketplace - biayaIklan - biayaOperasional - pajak;

    const roas = biayaIklan > 0 ? omset / biayaIklan : 0;
    const marginBersih = omset > 0 ? (labaBersih / omset) * 100 : 0;


const grossProfit = omset - discount - totalHpp - biayaMarketplace;
const bepRoas = grossProfit > 0 ? omset / grossProfit : 0;

let status = 'Data belum cukup';
if (biayaIklan > 0 && labaBersih > 0) status = 'PROFIT';
if (biayaIklan > 0 && labaBersih <= 0) status = 'RUGI / PERLU OPTIMASI';

return {
    omset,
    totalOrder,
    qtyTerjual,
    totalHpp,
    biayaMarketplace,
    biayaIklan,
    biayaOperasional,
    pajak,
    labaKotor,
    grossProfit,
    labaBersih,
    roas,
    marginBersih,
    bepRoas,
    discount,
    status
};
});

const dashboardFilteredData = computed(() => {
    const toSafeDate = (value) => {
        if (!value) return null;

        const d = value?.toDate
            ? value.toDate()
            : (value?.seconds ? new Date(value.seconds * 1000) : new Date(value));

        return isNaN(d.getTime()) ? null : d;
    };

    const mapToDateObject = (dataArray, type = 'default') => {
        return (dataArray || [])
            .map(item => {
                const tanggalTransaksi = toSafeDate(item.tanggal);
                const tanggalPencairan = toSafeDate(item.tanggalPencairan);

                let tanggalUntukFilter = tanggalTransaksi;

                // Untuk Dashboard Dana Cair:
                // Kalau transaksi sudah cair, filter waktunya pakai tanggal dana cair.
                if (type === 'transaksi' && item.statusPencairan === 'Sudah Cair') {
                    tanggalUntukFilter = tanggalPencairan || tanggalTransaksi;
                }

                return {
                    ...item,
                    tanggal: tanggalUntukFilter,
                    tanggalTransaksi,
                    tanggalPencairan
                };
            })
            .filter(item => item.tanggal);
    };

    const keuanganData = mapToDateObject(state.keuangan);
    const transaksiData = mapToDateObject(state.transaksi, 'transaksi');
    const returData = mapToDateObject(state.retur);

    const filterOptions = [
        uiState.dashboardDateFilter,
        uiState.dashboardStartDate,
        uiState.dashboardEndDate,
        uiState.dashboardStartMonth,
        uiState.dashboardStartYear,
        uiState.dashboardEndMonth,
        uiState.dashboardEndYear
    ];

    return {
        transaksi: filterDataByDate(transaksiData, ...filterOptions),
        keuangan: filterDataByDate(keuanganData, ...filterOptions),
        retur: filterDataByDate(returData, ...filterOptions)
    };
});

const filteredInvestorPayments = computed(() => {
    // Ambil data pembayaran dan pastikan array tidak null
    const payments = state.investorPayments || [];

    // Map data untuk membuat properti 'tanggal' yang aman sebelum filtering
    const paymentsForFilter = payments.map(p => {
        // Jika p.paymentDate null, gunakan Date(0) (tanggal awal) sebagai fallback yang aman
        const safeDate = p.paymentDate || new Date(0); 
        return { 
            ...p, 
            tanggal: safeDate 
        };
    });
    
    // 1. Terapkan filter tanggal (Filter Waktu)
    let filteredData = filterDataByDate(
        paymentsForFilter,
        uiState.investorPaymentFilter,
        uiState.investorPaymentStartDate,
        uiState.investorPaymentEndDate,
        uiState.investorPaymentStartMonth,
        uiState.investorPaymentStartYear,
        uiState.investorPaymentEndMonth,
        uiState.investorPaymentEndYear
    );

    // 2. Filter berdasarkan pencarian (diperkuat dengan guards)
    const searchQuery = uiState.investorPaymentSearch.toLowerCase();
    if (searchQuery) {
        filteredData = filteredData.filter(p => 
            // Pastikan kita tidak memanggil toLowerCase() pada null
            (p.investorName || '').toLowerCase().includes(searchQuery) ||
            (p.period || '').toLowerCase().includes(searchQuery) ||
            (p.paymentMethod || '').toLowerCase().includes(searchQuery) ||
            (p.bankDetails?.bankName || '').toLowerCase().includes(searchQuery)
        );
    }
    
    // 3. Sort: Terbaru lebih dulu (Desc)
    return filteredData.sort((a, b) => new Date(b.tanggal).getTime() - new Date(a.tanggal).getTime());
});

const investorLedger = computed(() => {
    // 1. Hitung total pembayaran per investor
    const paymentsByInvestor = (state.investorPayments || []).reduce((acc, p) => {
        const invId = p.investorId;
        if (!acc[invId]) {
            acc[invId] = { totalPayout: 0 };
        }
        // Pastikan totalPayment ada
        acc[invId].totalPayout += (p.totalPayment || 0); 
        return acc;
    }, {});

    // 2. Gabungkan dengan data investor dan hitung ROI
    return (state.investor || []).map(inv => {
        const totalPayout = paymentsByInvestor[inv.id]?.totalPayout || 0;
        const modal = inv.amount || 0;
        
        let roi = 0;
        if (modal > 0) {
            // ROI = (Total Dibayarkan / Modal) * 100
            roi = (totalPayout / modal) * 100;
        }

        return {
            ...inv,
            totalPayout: totalPayout,
            roi: roi,
            // Menggunakan Date.getTime() untuk memastikan nilai numerik yang dapat diurutkan
            startDate: inv.startDate instanceof Date ? inv.startDate.getTime() : new Date(inv.startDate).getTime()
        };
    }).filter(inv => {
        // Filter status
        if (uiState.investorStatusFilter === 'aktif') return inv.status === 'aktif';
        if (uiState.investorStatusFilter === 'selesai') return inv.status === 'selesai';
        return true; // 'semua'
    });
});

// GANTI SELURUH COMPUTED PROPERTY INI
const dashboardKpis = computed(() => {
    let kpis = {
        saldoKas: 0,
        omsetBersih: 0,
        labaKotor: 0,
        labaBersih: 0,
        omsetKotor: 0,
        totalDiskon: 0,
        totalHppTerjual: 0,
        totalBiayaTransaksi: 0,
        totalBiayaOperasional: 0,
        totalNilaiRetur: 0,
        pemasukanLain: 0,
        danaBelumCair: 0,
        qtyBelumCair: 0,
        totalUnitStok: 0,
        totalNilaiStokHPP: 0
    };

    const { transaksi, keuangan, retur } = dashboardFilteredData.value;

    let omsetKotorAwal = 0;
    let totalDiskonAwal = 0;
    let totalHppTerjualAwal = 0;
    let totalBiayaTransaksiAwal = 0;
    let danaBelumCair = 0;
    let qtyBelumCair = 0;

const transaksiCairKeys = new Set();

(transaksi || []).forEach(trx => {
    if (trx.statusPencairan === 'Sudah Cair') {
        [
            trx.id,
            trx.marketplaceOrderId,
            trx.orderId,
            trx.idPesanan,
            trx.nomorPesanan
        ]
            .filter(Boolean)
            .forEach(key => transaksiCairKeys.add(String(key).toLowerCase()));
    }
});

    (transaksi || []).forEach(trx => {
        
        const totalHppTrx = (trx.items || []).reduce((sum, item) => {
            return sum + ((Number(item.hpp) || 0) * (Number(item.qty) || 0));
        }, 0);

        const totalBiayaTrx = Number(trx.biaya?.total) || 0;

        const trxQty = (trx.items || []).reduce((sum, item) => {
            return sum + (Number(item.qty) || 0);
        }, 0);

        const isCair = trx.statusPencairan === 'Sudah Cair';
        const isPending = !trx.statusPencairan || trx.statusPencairan === 'Belum Cair' || trx.statusPencairan === 'Waiting';

        if (isCair) {
            omsetKotorAwal += Number(trx.subtotal) || 0;
            totalDiskonAwal += Number(trx.diskon?.totalDiscount) || 0;
            totalHppTerjualAwal += totalHppTrx;
            totalBiayaTransaksiAwal += totalBiayaTrx;
        } else if (isPending) {
            const payout = (Number(trx.total) || 0) - totalBiayaTrx;
            danaBelumCair += payout;
            qtyBelumCair += trxQty;
        }
    });

    kpis.danaBelumCair = danaBelumCair;
    kpis.qtyBelumCair = qtyBelumCair;

    // Semua retur pada filter Dashboard.
// Dipakai khusus untuk kartu Total Nilai Retur.
let totalNilaiReturSemua = 0;

// Retur dari transaksi Sudah Cair.
// Dipakai untuk koreksi omzet, HPP, biaya, dan laba.
let totalNilaiReturGross = 0;

let totalDiskonBatal = 0;
let totalHppRetur = 0;
let biayaMarketplaceBatal = 0;

    (retur || []).forEach(r => {
    // Seluruh data retur masuk ke kartu Total Nilai Retur,
    // baik dari Manajemen Retur maupun Audit & Pencairan Dana.
    (r.items || []).forEach(item => {
        totalNilaiReturSemua +=
            (Number(item.nilaiRetur) || 0) +
            (Number(item.nilaiDiskon) || 0);
    });

    const returKeys = [
        r.originalTransactionId,
        r.transactionId,
        r.marketplaceOrderId,
        r.orderId,
        r.idPesanan,
        r.nomorPesanan
    ]
        .filter(Boolean)
        .map(key => String(key).toLowerCase());

    const returPunyaTransaksiAsal = returKeys.some(key => transaksiCairKeys.has(key));

    if (!returPunyaTransaksiAsal) {
        return;
    }

    (r.items || []).forEach(item => {
        totalNilaiReturGross += (Number(item.nilaiRetur) || 0) + (Number(item.nilaiDiskon) || 0);
        totalDiskonBatal += Number(item.nilaiDiskon) || 0;
        biayaMarketplaceBatal += Number(item.biayaMarketplace) || 0;

        const product = getProductBySku(item.sku);

        if (product) {
            totalHppRetur += (Number(product.hpp) || 0) * (Number(item.qty) || 0);
        }
    });
});

    const pemasukanLain = (keuangan || [])
        .filter(k => k.jenis === 'pemasukan_lain')
        .reduce((sum, k) => sum + (Number(k.jumlah) || 0), 0);

    

    kpis.totalBiayaOperasional = (keuangan || [])
        .filter(k => k.jenis === 'pengeluaran' || k.jenis === 'biaya')
        .filter(k => (k.tipeBiaya || getExpenseTypeByCategory(k.kategori)) !== 'produksi')
        .reduce((sum, k) => sum + (Number(k.jumlah) || 0), 0);

    kpis.omsetKotor = omsetKotorAwal - totalNilaiReturGross;
    kpis.totalDiskon = totalDiskonAwal - totalDiskonBatal;
    kpis.totalHppTerjual = totalHppTerjualAwal - totalHppRetur;
    kpis.totalBiayaTransaksi = totalBiayaTransaksiAwal - biayaMarketplaceBatal;
    kpis.totalNilaiRetur = totalNilaiReturSemua;
    kpis.pemasukanLain = pemasukanLain;

    kpis.omsetBersih = kpis.omsetKotor - kpis.totalDiskon;
    kpis.labaKotor = kpis.omsetBersih - kpis.totalHppTerjual;
    kpis.labaBersih = kpis.labaKotor - kpis.totalBiayaTransaksi - kpis.totalBiayaOperasional;

        // SALDO KAS BERJALAN
    // Saldo Kas Berjalan tidak mengikuti filter waktu dashboard.
    // Angka ini dihitung dari semua transaksi yang sudah cair + pemasukan lain - pengeluaran kas.
    // Retur hanya dihitung jika transaksi asalnya masih ada, supaya retur yatim tidak membuat saldo kas ngaco.

    let saldoOmsetKotorAllTime = 0;
    let saldoDiskonAllTime = 0;
    let saldoBiayaTransaksiAllTime = 0;

    const saldoTransaksiCairKeys = new Set();

    (state.transaksi || []).forEach(trx => {
        if (trx.statusPencairan !== 'Sudah Cair') return;

        saldoOmsetKotorAllTime += Number(trx.subtotal) || 0;
        saldoDiskonAllTime += Number(trx.diskon?.totalDiscount) || 0;
        saldoBiayaTransaksiAllTime += Number(trx.biaya?.total) || 0;

        if (trx.id) saldoTransaksiCairKeys.add(String(trx.id).toLowerCase());
        if (trx.marketplaceOrderId) saldoTransaksiCairKeys.add(String(trx.marketplaceOrderId).toLowerCase());
        if (trx.orderId) saldoTransaksiCairKeys.add(String(trx.orderId).toLowerCase());
        if (trx.idPesanan) saldoTransaksiCairKeys.add(String(trx.idPesanan).toLowerCase());
        if (trx.nomorPesanan) saldoTransaksiCairKeys.add(String(trx.nomorPesanan).toLowerCase());
    });

    let saldoNilaiReturGrossAllTime = 0;
    let saldoDiskonBatalAllTime = 0;
    let saldoBiayaMarketplaceBatalAllTime = 0;

    (state.retur || []).forEach(r => {
        const returKeys = [
            r.originalTransactionId,
            r.transactionId,
            r.marketplaceOrderId,
            r.orderId,
            r.idPesanan,
            r.nomorPesanan
        ]
            .filter(Boolean)
            .map(key => String(key).toLowerCase());

        const returPunyaTransaksiAsal = returKeys.some(key => saldoTransaksiCairKeys.has(key));

        if (!returPunyaTransaksiAsal) {
            return;
        }

        (r.items || []).forEach(item => {
            saldoNilaiReturGrossAllTime += (Number(item.nilaiRetur) || 0) + (Number(item.nilaiDiskon) || 0);
            saldoDiskonBatalAllTime += Number(item.nilaiDiskon) || 0;
            saldoBiayaMarketplaceBatalAllTime += Number(item.biayaMarketplace) || 0;
        });
    });

    const saldoOmsetBersihAllTime =
        (saldoOmsetKotorAllTime - saldoNilaiReturGrossAllTime)
        - (saldoDiskonAllTime - saldoDiskonBatalAllTime);

    const saldoBiayaTransaksiFinalAllTime =
        saldoBiayaTransaksiAllTime - saldoBiayaMarketplaceBatalAllTime;

    const saldoPemasukanLainAllTime = (state.keuangan || [])
        .filter(k => k.jenis === 'pemasukan_lain')
        .reduce((sum, k) => sum + (Number(k.jumlah) || 0), 0);

    const saldoPengeluaranKasAllTime = (state.keuangan || [])
        .filter(k => k.jenis === 'pengeluaran' || k.jenis === 'biaya')
        .reduce((sum, k) => sum + (Number(k.jumlah) || 0), 0);

    kpis.saldoKas =
        (saldoOmsetBersihAllTime + saldoPemasukanLainAllTime)
        - (saldoBiayaTransaksiFinalAllTime + saldoPengeluaranKasAllTime);

    kpis.totalUnitStok = (state.produk || [])
        .reduce((sum, p) => sum + (Number(p.stokFisik) || 0), 0);

    kpis.totalNilaiStokHPP = (state.produk || [])
        .reduce((sum, p) => sum + ((Number(p.stokFisik) || 0) * (Number(p.hpp) || 0)), 0);

    return kpis;
});

const dataHealthAudit = computed(() => {
    const issues = [];

    const addIssue = (level, title, description, location) => {
        issues.push({
            id: `${level}-${title}-${issues.length}`,
            level,
            title,
            description,
            location
        });
    };

    (state.produk || []).forEach(product => {
        if (!product.sku) {
            addIssue(
                'danger',
                'Produk tanpa SKU',
                'Produk ini belum memiliki SKU. SKU dibutuhkan untuk stok, transaksi, retur, dan laporan.',
                product.nama || product.product_name || 'Produk'
            );
        }

        if (!product.hpp || Number(product.hpp) <= 0) {
            addIssue(
                'warning',
                'Produk belum punya HPP',
                'HPP kosong bisa membuat laba kotor dan laba bersih tidak akurat.',
                product.sku || product.nama || product.product_name || 'Produk'
            );
        }

        if ((Number(product.stokFisik) || 0) < 0) {
            addIssue(
                'danger',
                'Stok produk minus',
                'Stok minus menandakan ada transaksi, retur, atau penyesuaian stok yang perlu dicek.',
                product.sku || product.nama || product.product_name || 'Produk'
            );
        }
    });

    const skuMap = {};

    (state.produk || []).forEach(product => {
        if (!product.sku) return;

        const sku = String(product.sku).toLowerCase();
        skuMap[sku] = (skuMap[sku] || 0) + 1;
    });

    Object.keys(skuMap).forEach(sku => {
        if (skuMap[sku] > 1) {
            addIssue(
                'danger',
                'SKU duplikat',
                `SKU ini dipakai ${skuMap[sku]} kali. SKU duplikat bisa membuat transaksi dan stok salah baca.`,
                sku.toUpperCase()
            );
        }
    });

    (state.transaksi || []).forEach(trx => {
        if (!trx.statusPencairan) {
            addIssue(
                'warning',
                'Transaksi belum punya status pencairan',
                'Status pencairan kosong bisa membuat dashboard dana cair tidak akurat.',
                trx.id || trx.marketplaceOrderId || 'Transaksi'
            );
        }

        (trx.items || []).forEach(item => {
            if (!item.sku) {
                addIssue(
                    'danger',
                    'Item transaksi tanpa SKU',
                    'Ada item transaksi yang tidak memiliki SKU, sehingga stok dan laporan bisa salah.',
                    trx.id || trx.marketplaceOrderId || 'Transaksi'
                );
            }

            if (!item.hpp || Number(item.hpp) <= 0) {
                addIssue(
                    'warning',
                    'Item transaksi tanpa HPP',
                    'HPP pada item transaksi kosong. Laba transaksi bisa tidak akurat.',
                    item.sku || trx.id || 'Transaksi'
                );
            }
        });
    });

    const transaksiKeys = new Set();

    (state.transaksi || []).forEach(trx => {
        [
            trx.id,
            trx.marketplaceOrderId,
            trx.orderId,
            trx.idPesanan,
            trx.nomorPesanan
        ]
            .filter(Boolean)
            .forEach(key => transaksiKeys.add(String(key).toLowerCase()));
    });

    (state.retur || []).forEach(retur => {
        const returKeys = [
            retur.originalTransactionId,
            retur.transactionId,
            retur.marketplaceOrderId,
            retur.orderId,
            retur.idPesanan,
            retur.nomorPesanan
        ]
            .filter(Boolean)
            .map(key => String(key).toLowerCase());

        const punyaTransaksiAsal = returKeys.some(key => transaksiKeys.has(key));

        if (!punyaTransaksiAsal) {
            addIssue(
                'warning',
                'Retur tanpa transaksi asal',
                'Data retur ini tidak menemukan transaksi asal. Jika transaksi sudah dihapus, retur ini bisa membuat laporan terlihat minus.',
                retur.id || 'Retur'
            );
        }
    });

    (state.keuangan || []).forEach(item => {
        if (!item.kategori) {
            addIssue(
                'warning',
                'Data keuangan tanpa kategori',
                'Kategori kosong membuat laporan biaya operasional atau produksi sulit dibaca.',
                item.id || item.jenis || 'Keuangan'
            );
        }
    });

    return {
        issues,
        summary: {
            total: issues.length,
            danger: issues.filter(i => i.level === 'danger').length,
            warning: issues.filter(i => i.level === 'warning').length
        }
    };
});

