const laporanSemuanyaData = computed(() => {
    // Awalnya, ambil semua item produksi dari setiap batch
    let semuaItemProduksi = state.produksi.flatMap(batch =>
        (batch.kainBahan || []).map(kain => ({
            ...kain,
            batchId: batch.id,
            tanggal: batch.tanggal,
            namaStatus: batch.namaStatus, // Memastikan nama pekerja ada
            produksiType: batch.produksiType, // Memastikan jenis pekerja ada
            statusProses: batch.statusProses,
        }))
    );

    // Filter berdasarkan jenis pekerja yang dipilih
    if (uiState.produksiFilterType !== 'all') {
        semuaItemProduksi = semuaItemProduksi.filter(item => item.produksiType === uiState.produksiFilterType);
    }
    
    // Terapkan filter tanggal setelah filter jenis pekerja
    const filteredData = filterDataByDate(
        semuaItemProduksi,
        uiState.laporanSemuaFilter,
        uiState.laporanSemuaStartDate,
        uiState.laporanSemuaEndDate,
        uiState.laporanSemuaStartMonth,
        uiState.laporanSemuaStartYear,
        uiState.laporanSemuaEndMonth,
        uiState.laporanSemuaEndYear
    );

    const tableData = filteredData.map(item => {
        const modelInfo = state.settings.modelProduk.find(m => m.id === item.modelProdukId) || {};
        const totalBiayaKain = (item.totalYard || 0) * (item.hargaKainPerYard || 0);
        const hargaJasaPerPcs = item.produksiType === 'penjahit' ? (item.hargaJahitPerPcs || 0) : (item.hargaMaklunPerPcs || 0);
        
        // [PERBAIKAN KUNCI DI SINI]
        // Biaya Jasa dan Biaya Alat sekarang HANYA dihitung berdasarkan 'aktualJadi'
        const totalBiayaJasa = (item.aktualJadi || 0) * hargaJasaPerPcs;
        const totalBiayaAlat = (item.aktualJadi || 0) > 0 ? (item.biayaAlat || 0) : 0;
        
        const totalBiayaProduksi = totalBiayaKain + totalBiayaJasa + totalBiayaAlat;
        
        return {
            ...item,
            modelNama: modelInfo.namaModel || 'N/A',
            totalBiayaKain,
            totalBiayaMaklun: totalBiayaJasa,
            totalBiayaAlat,
            totalBiayaProduksi,
            totalKuantitas: (item.aktualJadi || 0) + (item.aktualJadiKombinasi || 0),
        };
    }).sort((a, b) => new Date(b.tanggal) - new Date(a.tanggal));

    return { tableData };
});


const laporanSemuaKpis = computed(() => {
    const tableData = laporanSemuanyaData.value.tableData;
    if (!tableData || tableData.length === 0) {
        return { totalModelSelesai: 0, totalBiaya: 0, avgHpp: 0, totalBatch: 0 };
    }

    // [PERBAIKAN] Hanya menghitung dari 'aktualJadi' sesuai permintaan
    const totalModelSelesai = tableData.reduce((sum, item) => sum + (item.aktualJadi || 0), 0);

    const totalBiaya = tableData.reduce((sum, item) => sum + item.totalBiayaProduksi, 0);
    const avgHpp = totalModelSelesai > 0 ? totalBiaya / totalModelSelesai : 0;
    const totalBatch = new Set(tableData.map(item => item.batchId)).size;

    return { totalModelSelesai, totalBiaya, avgHpp, totalBatch };
});
const analisisModelData = computed(() => {
    console.log("--- MEMULAI ANALISIS ---");

    const dataPerKain = state.produksi.flatMap(batch =>
        (batch.kainBahan || []).map(kain => ({
            ...kain,
            batchId: batch.id,
            tanggal: batch.tanggal,
            namaStatus: batch.namaStatus,
            produksiType: batch.produksiType,
            statusProses: batch.statusProses,
        }))
    );
    console.log("1. Total item produksi yang ditemukan:", dataPerKain.length, dataPerKain);
    console.log("2. Filter yang sedang aktif:", { 
        filterMode: uiState.analisisModelFilter,
        selectedModelId: uiState.analisisModelSelectedModel, 
        workerType: uiState.produksiFilterType,
        actualType: uiState.analisisModelSelectedType
    });

    let filteredData = dataPerKain.filter(item => {
        const matchesType = uiState.produksiFilterType === 'all' || item.produksiType === uiState.produksiFilterType;
        const matchesModel = uiState.analisisModelFilter === 'all' || (uiState.analisisModelFilter === 'model' && item.modelProdukId === uiState.analisisModelSelectedModel);
        return matchesType && matchesModel;
    });
    console.log("3. Data setelah difilter berdasarkan Model & Jenis Status:", filteredData.length, filteredData);

    const processedData = filteredData.map(item => {
        const modelInfo = state.settings.modelProduk.find(m => m.id === item.modelProdukId) || {};
        const totalBiayaKain = (item.totalYard || 0) * (item.hargaKainPerYard || 0);
        const yardStandar = modelInfo.yardPerModel || 1;
        const hargaJasaPerPcs = item.produksiType === 'penjahit' ? (item.hargaJahitPerPcs || 0) : (item.hargaMaklunPerPcs || 0);
        const targetQty = Math.floor((item.totalYard || 0) / yardStandar);
        let aktualFinal = 0;
        let totalBiayaJasa = 0;
        let totalBiayaAlat = 0;
        if (uiState.analisisModelSelectedType === 'aktualJadi' && item.aktualJadi > 0) {
            aktualFinal = (item.aktualJadi || 0);
            totalBiayaJasa = aktualFinal * hargaJasaPerPcs;
            totalBiayaAlat = (item.biayaAlat || 0);
        } else if (uiState.analisisModelSelectedType === 'aktualJadiKombinasi' && item.aktualJadiKombinasi > 0) {
            aktualFinal = (item.aktualJadiKombinasi || 0);
            totalBiayaJasa = 0;
            totalBiayaAlat = 0;
        }
        const selisih = aktualFinal - targetQty;
        const totalBiayaProduksi = totalBiayaKain + totalBiayaJasa + totalBiayaAlat;
        const hpp = totalBiayaProduksi / (aktualFinal || 1);
        return {
            ...item,
            modelNama: modelInfo.namaModel || 'N/A',
            targetQty: targetQty,
            aktualFinal: aktualFinal,
            selisih: selisih,
            hpp: hpp,
        };
    });
    console.log("4. Data setelah diproses (sebelum filter aktual > 0):", processedData.length, processedData);
    
    const finalData = processedData.filter(item => item.aktualFinal > 0);
    console.log("5. Data FINAL yang akan ditampilkan di tabel:", finalData.length, finalData);

    const sortedData = finalData.sort((a, b) => a.selisih - b.selisih);
    const limit = parseInt(uiState.analisisModelLimit, 10);
    const finalResult = limit > 0 ? sortedData.slice(0, limit) : sortedData;
    console.log("--- ANALISIS SELESAI ---");
    return finalResult;
});

const dashboardPremiumData = computed(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    const transaksiHariIni = (state.transaksi || []).filter(t => {
        const d = new Date(t.tanggal);
        return d >= today && d < tomorrow;
    });

    const omsetHariIni = transaksiHariIni.reduce((sum, t) => {
        return sum + (t.subtotal || t.total || 0);
    }, 0);

    const hppHariIni = transaksiHariIni.reduce((sum, t) => {
        return sum + (t.items || []).reduce((s, item) => {
            return s + ((item.hpp || 0) * (item.qty || 0));
        }, 0);
    }, 0);

    const biayaTransaksiHariIni = transaksiHariIni.reduce((sum, t) => {
        return sum + (t.biaya?.total || 0);
    }, 0);

    const biayaOperasionalHariIni = (state.keuangan || [])
    .filter(k => {
        const d = k.tanggal?.toDate
            ? k.tanggal.toDate()
            : (k.tanggal instanceof Date ? k.tanggal : new Date(k.tanggal));

        return d >= today &&
            d < tomorrow &&
            (k.jenis === 'pengeluaran' || k.jenis === 'biaya') &&
            (k.tipeBiaya || getExpenseTypeByCategory(k.kategori)) !== 'produksi';
    })
    .reduce((sum, k) => sum + (Number(k.jumlah) || 0), 0);

    const profitBersihHariIni =
    omsetHariIni -
    hppHariIni -
    biayaTransaksiHariIni -
    biayaOperasionalHariIni;

    const produkTerjualHariIni = transaksiHariIni.reduce((sum, t) => {
        return sum + (t.items || []).reduce((s, item) => {
            return s + (item.qty || 0);
        }, 0);
    }, 0);

    const produkHampirHabis = (state.produk || [])
        .filter(p => {
            const stok = p.stokFisik ?? p.physical_stock ?? 0;
            return stok > 0 && stok <= (state.settings.minStok || 10);
        })
        .sort((a, b) => {
            const stokA = a.stokFisik ?? a.physical_stock ?? 0;
            const stokB = b.stokFisik ?? b.physical_stock ?? 0;
            return stokA - stokB;
        })
        .slice(0, 5)
        .map(p => ({
            nama: p.nama || p.product_name || '-',
            warna: p.warna || p.color || '-',
            varian: p.varian || p.variant || '-',
            stok: p.stokFisik ?? p.physical_stock ?? 0
        }));

    const batchBelumSelesai = (state.produksi || []).filter(p => {
        return (p.statusProses || '').toLowerCase() !== 'selesai';
    });

    const maklunTerlambat = batchBelumSelesai.filter(p => {
        const d = new Date(p.tanggal);
        const umurHari = Math.floor((today - d) / (1000 * 60 * 60 * 24));

        return (p.produksiType || '').toLowerCase() === 'pemaklun' &&
            umurHari >= 14;
    });

    return {
        omsetHariIni,
        profitBersihHariIni,
        orderHariIni: transaksiHariIni.length,
        produkTerjualHariIni,
        produkHampirHabis,
        batchBelumSelesai: batchBelumSelesai.length,
        maklunTerlambat: maklunTerlambat.length
    };
});



const dashboardSalesStats = computed(() => {
    const modelMap = {};
    const colorMap = {};
    const sizeMap = {};
    const channelMap = {};

    const selectedModel = uiState.dashboardSalesModelFilter;
    const selectedChannel = uiState.dashboardSalesChannelFilter;

    (state.transaksi || []).forEach(transaksi => {
        const channelName = transaksi.channel || transaksi.channelId || 'Tanpa Channel';

        if (selectedChannel !== 'all' && channelName !== selectedChannel) {
            return;
        }

        (transaksi.items || []).forEach(item => {
            const qty = item.qty || 0;

            const productData = (state.produk || []).find(p =>
                p.sku === item.sku ||
                p.docId === item.product_id ||
                p.id === item.product_id
            );

            const masterModel = (state.settings.modelProduk || []).find(m =>
                m.id === productData?.model_id ||
                m.id === productData?.modelId ||
                m.id === item.modelProdukId ||
                m.id === item.model_id
            );

            const modelName = masterModel?.namaModel || 'Tanpa Model';

            if (selectedModel !== 'all' && modelName !== selectedModel) {
                return;
            }

            const colorName =
                item.warna ||
                item.color ||
                productData?.warna ||
                productData?.color ||
                'Tanpa Warna';

            const sizeName =
                item.varian ||
                item.size ||
                item.ukuran ||
                productData?.varian ||
                productData?.variant ||
                productData?.ukuran ||
                'Tanpa Ukuran';

            const itemOmset = (item.hargaJual || item.price || item.harga || 0) * qty;

            if (!modelMap[modelName]) modelMap[modelName] = { name: modelName, qty: 0 };
            if (!colorMap[colorName]) colorMap[colorName] = { name: colorName, qty: 0 };
            if (!sizeMap[sizeName]) sizeMap[sizeName] = { name: sizeName, qty: 0 };
            if (!channelMap[channelName]) channelMap[channelName] = { name: channelName, qty: 0, omset: 0 };

            modelMap[modelName].qty += qty;
            colorMap[colorName].qty += qty;
            sizeMap[sizeName].qty += qty;
            channelMap[channelName].qty += qty;
            channelMap[channelName].omset += itemOmset;
        });
    });

    const sortByQty = data => Object.values(data).sort((a, b) => b.qty - a.qty).slice(0, 3);
    const sortByOmset = data => Object.values(data).sort((a, b) => b.omset - a.omset).slice(0, 3);

    return {
        topModels: sortByQty(modelMap),
        topColors: sortByQty(colorMap),
        topSizes: sortByQty(sizeMap),
        topChannels: sortByOmset(channelMap)
    };
});

const salesPerformanceStats = computed(() => {
    const selectedDate = uiState.salesStatsDateFilter;
    const selectedModel = uiState.salesStatsModelFilter;
    const selectedChannel = uiState.salesStatsChannelFilter;

    const modelMap = {};
    const colorMap = {};
    const sizeMap = {};
    const channelMap = {};
    const productMap = {};

    let totalOrder = 0;
    let totalQty = 0;
    let totalOmset = 0;
    let totalHpp = 0;

    const toDate = (value) => {
        if (!value) return null;
        const date = value?.toDate
            ? value.toDate()
            : value?.seconds
                ? new Date(value.seconds * 1000)
                : new Date(value);

        return isNaN(date.getTime()) ? null : date;
    };

    const isDateIncluded = (dateValue) => {
        if (selectedDate === 'all_time') return true;

        const date = toDate(dateValue);
        if (!date) return false;

        const now = new Date();

        const startToday = new Date();
        startToday.setHours(0, 0, 0, 0);

        const endToday = new Date();
        endToday.setHours(23, 59, 59, 999);

        if (selectedDate === 'today') {
            return date >= startToday && date <= endToday;
        }

        if (selectedDate === 'last_7_days') {
            const start = new Date();
            start.setDate(now.getDate() - 7);
            start.setHours(0, 0, 0, 0);
            return date >= start && date <= now;
        }

        if (selectedDate === 'last_30_days') {
            const start = new Date();
            start.setDate(now.getDate() - 30);
            start.setHours(0, 0, 0, 0);
            return date >= start && date <= now;
        }

        if (selectedDate === 'this_month') {
            return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
        }

        return true;
    };

    (state.transaksi || []).forEach(trx => {
        if (!isDateIncluded(trx.tanggal)) return;

        const channelName = trx.channel || trx.channelId || 'Tanpa Channel';

        if (selectedChannel !== 'all' && channelName !== selectedChannel) {
            return;
        }

        let trxIncluded = false;

        (trx.items || []).forEach(item => {
            const qty = Number(item.qty) || 0;
            if (qty <= 0) return;

            const productData = (state.produk || []).find(p =>
                p.sku === item.sku ||
                p.docId === item.product_id ||
                p.id === item.product_id
            );

            const masterModel = (state.settings.modelProduk || []).find(m =>
                m.id === productData?.model_id ||
                m.id === productData?.modelId ||
                m.id === item.modelProdukId ||
                m.id === item.model_id
            );

            const modelName =
                item.modelName ||
                masterModel?.namaModel ||
                productData?.nama ||
                productData?.product_name ||
                'Tanpa Model';

            if (selectedModel !== 'all' && modelName !== selectedModel) {
                return;
            }

            trxIncluded = true;

            const colorName =
                item.warna ||
                item.color ||
                productData?.warna ||
                productData?.color ||
                'Tanpa Warna';

            const sizeName =
                item.varian ||
                item.size ||
                item.ukuran ||
                productData?.varian ||
                productData?.variant ||
                productData?.ukuran ||
                'Tanpa Ukuran';

            const productName =
                productData?.nama ||
                productData?.product_name ||
                modelName;

            const sku = item.sku || productData?.sku || '-';

            const hargaJual = Number(item.hargaJual || item.price || item.harga || 0);
            const hpp = Number(item.hpp || productData?.hpp || 0);

            const itemOmset = hargaJual * qty;
            const itemHpp = hpp * qty;
            const itemProfit = itemOmset - itemHpp;

            totalQty += qty;
            totalOmset += itemOmset;
            totalHpp += itemHpp;

            if (!modelMap[modelName]) {
                modelMap[modelName] = { name: modelName, qty: 0, omset: 0, profit: 0 };
            }

            if (!colorMap[colorName]) {
                colorMap[colorName] = { name: colorName, qty: 0, omset: 0 };
            }

            if (!sizeMap[sizeName]) {
                sizeMap[sizeName] = { name: sizeName, qty: 0, omset: 0 };
            }

            if (!channelMap[channelName]) {
                channelMap[channelName] = { name: channelName, qty: 0, omset: 0, order: 0 };
            }

            if (!productMap[sku]) {
                productMap[sku] = {
                    sku,
                    name: productName,
                    model: modelName,
                    color: colorName,
                    size: sizeName,
                    qty: 0,
                    omset: 0,
                    hpp: 0,
                    profit: 0
                };
            }

            modelMap[modelName].qty += qty;
            modelMap[modelName].omset += itemOmset;
            modelMap[modelName].profit += itemProfit;

            colorMap[colorName].qty += qty;
            colorMap[colorName].omset += itemOmset;

            sizeMap[sizeName].qty += qty;
            sizeMap[sizeName].omset += itemOmset;

            channelMap[channelName].qty += qty;
            channelMap[channelName].omset += itemOmset;

            productMap[sku].qty += qty;
            productMap[sku].omset += itemOmset;
            productMap[sku].hpp += itemHpp;
            productMap[sku].profit += itemProfit;
        });

        if (trxIncluded) {
            totalOrder += 1;
            if (channelMap[channelName]) {
                channelMap[channelName].order += 1;
            }
        }
    });

    const sortByQty = (data) => Object.values(data).sort((a, b) => b.qty - a.qty);
    const sortByOmset = (data) => Object.values(data).sort((a, b) => b.omset - a.omset);

    const grossProfit = totalOmset - totalHpp;

    return {
        totalOrder,
        totalQty,
        totalOmset,
        totalHpp,
        grossProfit,
        averageOrderValue: totalOrder > 0 ? totalOmset / totalOrder : 0,

        topModels: sortByQty(modelMap).slice(0, 10),
        topColors: sortByQty(colorMap).slice(0, 10),
        topSizes: sortByQty(sizeMap).slice(0, 10),
        topChannels: sortByOmset(channelMap).slice(0, 10),
        topProducts: sortByOmset(productMap).slice(0, 20)
    };
});

