// FUNGSI HAPUS RETUR (SEKARANG LEBIH SEDERHANA)

async function deleteReturnItem(itemToDelete) {
    const yakin = confirm(
        "Yakin ingin menghapus data retur ini?\n\nCatatan: penghapusan ini hanya menghapus riwayat retur. Stok inventaris tidak akan berubah."
    );

    if (!yakin) return;

    try {
        const returnDocRef = doc(db, "returns", itemToDelete.returnDocId);
        const returnSnap = await getDoc(returnDocRef);

        if (!returnSnap.exists()) {
            throw new Error("Data retur tidak ditemukan.");
        }

        const returnData = returnSnap.data();
        const oldItems = returnData.items || [];

        const newItems = oldItems.filter(item => {
            return !(
                item.sku === itemToDelete.sku &&
                item.qty === itemToDelete.qty &&
                item.alasan === itemToDelete.alasan
            );
        });

        if (newItems.length === 0) {
            await deleteDoc(returnDocRef);

            state.retur = state.retur.filter(r => r.id !== itemToDelete.returnDocId);
        } else {
            await updateDoc(returnDocRef, {
                items: newItems
            });

            const returInState = state.retur.find(r => r.id === itemToDelete.returnDocId);

            if (returInState) {
                returInState.items = newItems;
            }
        }

        

        alert("Data retur berhasil dihapus. Stok inventaris tidak berubah.");

    } catch (error) {
        console.error("Gagal menghapus data retur:", error);
        alert("Gagal menghapus data retur: " + error.message);
    }
}

function buildReturnItemsFromTransaction(
    transaction,
    itemsToReturn = [],
    defaultReason = ''
) {
    const transactionItems = Array.isArray(transaction?.items)
        ? transaction.items
        : [];

    // Gunakan subtotal tersimpan.
    // Untuk data lama yang tidak mempunyai subtotal,
    // hitung ulang dari seluruh item transaksi.
    const fallbackSubtotal = transactionItems.reduce((sum, item) => {
        const qty = Number(item.qty) || 0;

        const hargaJual = Number(
            item.hargaJualAktual ??
            item.hargaJual ??
            item.price ??
            item.harga ??
            0
        ) || 0;

        return sum + (hargaJual * qty);
    }, 0);

    const subtotalTransaksi =
        Number(transaction?.subtotal) ||
        fallbackSubtotal ||
        1;

    const totalDiskon =
        Number(transaction?.diskon?.totalDiscount) || 0;

    const totalBiayaMarketplace =
        Number(transaction?.biaya?.total) || 0;

    return (itemsToReturn || [])
        .map(item => {
            const qty =
                Number(item.returnQty ?? item.qty) || 0;

            const hargaJual = Number(
                item.hargaJualAktual ??
                item.hargaJual ??
                item.price ??
                item.harga ??
                0
            ) || 0;

            const nilaiKotorItem = hargaJual * qty;

            const porsiItem =
                subtotalTransaksi > 0
                    ? nilaiKotorItem / subtotalTransaksi
                    : 0;

            const nilaiDiskon =
                totalDiskon * porsiItem;

            const biayaMarketplace =
                totalBiayaMarketplace * porsiItem;

            const nilaiReturBersih =
                nilaiKotorItem - nilaiDiskon;

            return {
                sku: item.sku || '',
                qty,
                nilaiRetur: nilaiReturBersih,
                nilaiDiskon,
                biayaMarketplace,
                alasan:
                    item.alasan ||
                    defaultReason ||
                    ''
            };
        })
        .filter(item => item.sku && item.qty > 0);
}


// Mengumpulkan jumlah stok yang perlu dikembalikan.
// Map dipakai agar satu SKU hanya diperbarui sekali.
function addReturnedItemsToStockMap(stockMap, returnItems = []) {
    (returnItems || []).forEach(item => {
        const sku = String(item.sku || '').trim();
        const qty = Number(item.qty) || 0;

        if (!sku || qty <= 0) return;

        stockMap.set(
            sku,
            (stockMap.get(sku) || 0) + qty
        );
    });
}


// Memasukkan pengembalian stok fisik ke Firebase batch.
function queuePhysicalStockReturn(batch, stockMap) {
    stockMap.forEach((qty, sku) => {
        const product =
            getProductBySku(sku) ||
            state.inventoryPaginated.find(p =>
                String(p.sku || '').toLowerCase() ===
                sku.toLowerCase()
            );

        if (!product?.docId) {
            throw new Error(
                `Produk dengan SKU "${sku}" tidak ditemukan di Inventaris. Retur dibatalkan agar stok tidak salah.`
            );
        }

        const productRef = doc(
            db,
            "products",
            product.docId
        );

        // Increment menghitung langsung di server Firebase.
        batch.update(productRef, {
            physical_stock: increment(qty)
        });
    });
}


// Memperbarui tampilan stok setelah Firebase berhasil.
function applyPhysicalStockReturnToLocal(stockMap) {
    stockMap.forEach((qty, sku) => {
        const normalizedSku = sku.toLowerCase();

        const productInState = state.produk.find(p =>
            String(p.sku || '').toLowerCase() ===
            normalizedSku
        );

        if (productInState) {
            productInState.stokFisik =
                (Number(productInState.stokFisik) || 0) +
                qty;
        }

        const inventoryProduct =
            state.inventoryPaginated.find(p =>
                String(p.sku || '').toLowerCase() ===
                normalizedSku
            );

        if (inventoryProduct) {
            inventoryProduct.stokFisik =
                (Number(inventoryProduct.stokFisik) || 0) +
                qty;
        }
    });
}

async function submitReturForm() {
    if (!currentUser.value) return alert("Anda harus login.");
    const form = uiState.modalData;
    const selectedItems = form.items.filter(item => item.selected && item.returnQty > 0);

    if (!form.foundTransaction || selectedItems.length === 0) {
        alert('Harap cari transaksi dan pilih minimal satu item untuk diretur.');
        return;
    }

    try {
        const batch = writeBatch(db);
const trxAsli = form.foundTransaction;
const newKeuanganEntries = [];

// Menampung stok fisik yang akan dikembalikan
const returnedStockMap = new Map();

        const dataToSave = {
    tanggal: new Date(),
    channelId: trxAsli.channelId,
    originalTransactionId: trxAsli.id,

    items: buildReturnItemsFromTransaction(
        trxAsli,
        selectedItems,
        'Retur dari Manajemen Retur'
    ),

    userId: currentUser.value.uid
};

        const returnRef = doc(collection(db, "returns"));
        batch.set(returnRef, dataToSave);

        // Kumpulkan jumlah stok dari seluruh item retur
addReturnedItemsToStockMap(
    returnedStockMap,
    dataToSave.items
);

// Kembalikan stok fisik dalam batch yang sama
queuePhysicalStockReturn(
    batch,
    returnedStockMap
);
        
        await batch.commit();

        state.retur.unshift({ id: returnRef.id, ...dataToSave });
        if (newKeuanganEntries.length > 0) {
            state.keuangan.push(...newKeuanganEntries);
        }

        // Firebase sudah berhasil.
// Sekarang perbarui angka stok yang tampil.
applyPhysicalStockReturnToLocal(
    returnedStockMap
);

        alert(`Data retur untuk pesanan ${trxAsli.marketplaceOrderId} berhasil disimpan!`);
        hideModal();

    } catch (error) {
        console.error("Error menyimpan data retur:", error);
        alert("Gagal menyimpan data retur. Cek console untuk detail.");
    }
}

function handleReturPageSearch() {
    const query = uiState.returPageSearchQuery;
    if (!query) {
        uiState.returPageSearchRecommendations = [];
        return;
    }
    const lowerQuery = query.toLowerCase();
    const recommendations = new Set();
    
    // Cari berdasarkan SKU, Nama, Alasan dari data retur yang sudah ada
    // Perbaikan untuk memastikan tidak error saat ada data kosong
    state.retur.forEach(item => {
        // Karena data retur sekarang bisa memiliki banyak item di dalam array 'items'
        // Kita perlu meloop di dalamnya juga
        (item.items || []).forEach(itemDetail => {
            const product = getProductBySku(itemDetail.sku);
            const productName = product ? product.nama : '';

            const matches = (item.id && item.id.toLowerCase().includes(lowerQuery)) ||
                            (itemDetail.sku && itemDetail.sku.toLowerCase().includes(lowerQuery)) ||
                            (productName && productName.toLowerCase().includes(lowerQuery)) ||
                            (itemDetail.alasan && itemDetail.alasan.toLowerCase().includes(lowerQuery));

            if (matches) {
                if (itemDetail.sku) recommendations.add(itemDetail.sku);
                if (productName) recommendations.add(productName);
                if (itemDetail.alasan) recommendations.add(itemDetail.alasan);
            }
        });
    });

    uiState.returPageSearchRecommendations = Array.from(recommendations).slice(0, 5);
}

function selectReturPageRecommendation(rec) {
    uiState.returPageSearchQuery = rec;
    uiState.returPageSearchRecommendations = [];
}
