async function saveStockAllocation() {
    // --- 1. GEMBOK PENGAMAN ---
    if (isSaving.value) return;

    if (!currentUser.value) return alert("Anda harus login untuk menyimpan perubahan.");
    const modalData = uiState.modalData;

    if (!modalData || !modalData.product || !modalData.original) {
        console.error("Data modal tidak lengkap atau undefined.");
        alert("Gagal menyimpan: Data produk hilang.");
        return;
    }
    
    const { product, original } = modalData;
    const userId = currentUser.value.uid;
    const cleanAllocationData = JSON.parse(JSON.stringify(product.stokAlokasi));
    
    // KUNCI TOMBOL
    isSaving.value = true;

    try {
        const batch = writeBatch(db);

        const productRef = doc(db, "products", original.docId);
        
        // Update Stok Fisik (Override sesuai inputan user di form)
        batch.update(productRef, { physical_stock: product.stokFisik || 0 });
        
        // Update Alokasi
        const allocationRef = doc(db, "stock_allocations", original.docId);
        batch.set(allocationRef, { ...cleanAllocationData, userId: userId }, { merge: true });

        await batch.commit();

        // Update State Lokal
        const index = state.produk.findIndex(p => p.docId === original.docId);
        if (index !== -1) {
            state.produk[index].stokFisik = product.stokFisik || 0;
            state.produk[index].stokAlokasi = { ...product.stokAlokasi };
        }

        const inventoryIndex = state.inventoryPaginated.findIndex(p => p.docId === original.docId);
        if (inventoryIndex !== -1) {
            state.inventoryPaginated[inventoryIndex].stokFisik = product.stokFisik || 0;
            state.inventoryPaginated[inventoryIndex].stokAlokasi = { ...product.stokAlokasi };
        }

        const targetModel = state.settings.modelProduk.find(m => m.id === original.model_id);
        if (targetModel) {
            lastEditedModel.value = targetModel.namaModel.split(' ')[0];
        }
        
        hideModal();
        alert("Perubahan stok fisik dan alokasi berhasil disimpan!");

    } catch (error) {
        console.error("Error menyimpan alokasi stok:", error);
        alert(`Gagal menyimpan perubahan stok: ${error.message}`);
    } finally {
        // BUKA KUNCI
        isSaving.value = false;
    }
}

async function deleteGroup(variants) {
    if (!confirm(`Anda yakin ingin menghapus SEMUA ${variants.length} varian produk ini? Aksi ini tidak dapat dibatalkan.`)) {
        return;
    }
    if (!currentUser.value) {
        return alert("Anda harus login.");
    }

    const batch = writeBatch(db);
    const deletedDocIds = variants.map(v => v.docId);

    deletedDocIds.forEach(productId => {
        const productRef = doc(db, "products", productId);
        batch.delete(productRef);
        const allocationRef = doc(db, "stock_allocations", productId);
        batch.delete(allocationRef);

        state.settings.marketplaces.forEach(mp => {
            const priceDocId = `${productId}-${mp.id}`;
            const priceRef = doc(db, "product_prices", priceDocId);
            batch.delete(priceRef);
        });
    });

    try {
        await batch.commit();

        // --- PERBAIKAN DI SINI ---
        // Memperbarui kedua state array untuk konsistensi data dan UI
        state.produk = state.produk.filter(p => !deletedDocIds.includes(p.docId));
        state.inventoryPaginated = state.inventoryPaginated.filter(p => !deletedDocIds.includes(p.docId));
        
        alert(`Berhasil menghapus ${variants.length} varian produk.`);
    } catch (error) {
        console.error("Gagal menghapus grup produk:", error);
        alert(`Gagal menghapus produk: ${error.message}`);
    }
}

async function removeProductVariant(productId) {
    if (!confirm(`Anda yakin ingin menghapus varian produk ini? Aksi ini tidak dapat dibatalkan.`)) {
        return;
    }
    if (!currentUser.value) {
        return alert("Anda harus login.");
    }

    try {
        const batch = writeBatch(db);
        
        // DIHAPUS: Pengecekan di sisi klien yang menyebabkan error. Keamanan sudah diatur oleh Firebase Rules.
        // const productInState = state.produk.find(p => p.docId === productId);
        // if (!productInState || productInState.userId !== userId) {
        //     throw new Error("Anda tidak memiliki izin untuk menghapus produk ini.");
        // }

        const productRef = doc(db, "products", productId);
        batch.delete(productRef);
        const allocationRef = doc(db, "stock_allocations", productId);
        batch.delete(allocationRef);

        state.settings.marketplaces.forEach(mp => {
            const priceDocId = `${productId}-${mp.id}`;
            const priceRef = doc(db, "product_prices", priceDocId);
            batch.delete(priceRef);
        });

        await batch.commit();
        
        // --- PERBAIKAN DI SINI ---
        // Memperbarui kedua state array untuk konsistensi data dan UI
        state.produk = state.produk.filter(p => p.docId !== productId);
        state.inventoryPaginated = state.inventoryPaginated.filter(p => p.docId !== productId);

        alert(`Varian produk berhasil dihapus.`);
    } catch (error) {
        console.error(`Error menghapus produk ID: ${productId}:`, error);
        alert(`Gagal menghapus produk: ${error.message}`);
    }
}

function goToAturHarga(productName) {
