    uiState.bulkPasteValidation = null;
});
watch(() => uiState.activeCartChannel, (newChannel) => { if (newChannel && !state.carts[newChannel]) state.carts[newChannel] = []; });
watch(() => uiState.promosiSelectedModel, (newModel) => {
  if (newModel) {
    if (!state.promotions.perModel[newModel]) {
      state.promotions.perModel[newModel] = {};
    }
    state.settings.marketplaces.forEach(channel => {
      if (!state.promotions.perModel[newModel][channel.id]) {
        state.promotions.perModel[newModel][channel.id] = { minBelanja: null, diskonRate: null, diskonBertingkat: [] };
      }
    });
  }
});

watch(() => uiState.bulk_scan_input, (newValue) => {
    // 1. Jika kosong, abaikan
    if (!newValue || newValue.trim() === '') return;

    // 2. Clear timer lama
    if (bulkScanTimer) clearTimeout(bulkScanTimer);

    // 3. Buat timer baru (Tunggu 500ms)
    bulkScanTimer = setTimeout(() => {
        const scannedValue = newValue.trim();

        // 4. [PENTING] Cek Panjang Karakter
        // Jangan proses jika cuma 1 atau 2 huruf (seperti 's' atau 'sl')
        // Ini mencegah error muncul saat scanner baru mulai mengetik
        if (scannedValue.length < 3) {
            return; 
        }

        // Jika panjang sudah oke (minimal 3 huruf), baru proses
        prosesBulkScanFinal(scannedValue);

    }, 500); 
});

