let unsubscribe = () => {}; 

const setupListeners = async (
    userId,
    isUserPartner
) => {
    unsubscribe();

    // Komisi mitra tetap real-time.
    let commissionsListener = () => {};

    if (isUserPartner) {
        const commissionsQuery = query(
            collection(db, 'commissions'),
            where('partnerId', '==', userId)
        );

        commissionsListener = onSnapshot(
            commissionsQuery,
            (snapshot) => {
                commissions.value =
                    snapshot.docs.map(docSnap => ({
                        id: docSnap.id,
                        ...docSnap.data()
                    }));
            }
        );
    }

    unsubscribe = () => {
        commissionsListener();
    };
};

const fetchCoreData = async (
    userId,
    forceRefresh = false
) => {
    if (!userId) return;

    if (
        !forceRefresh &&
        dataFetched.settings
    ) {
        console.log(
            '[CACHE SESSION] Pengaturan, kategori, promosi, dan komisi produk sudah tersedia.'
        );

        return;
    }

    try {
        const readDocument =
            forceRefresh
                ? getDocFromServer
                : getDoc;

        const readDocuments =
            forceRefresh
                ? getDocsFromServer
                : getDocs;

        const categoriesQuery = query(
            collection(db, 'categories'),
            where('userId', '==', userId)
        );

        const [
            settingsSnap,
            promotionsSnap,
            commissionsSnap,
            categoriesSnap
        ] = await Promise.all([
            readDocument(
                doc(db, 'settings', userId)
            ),

            readDocument(
                doc(db, 'promotions', userId)
            ),

            readDocument(
                doc(
                    db,
                    'product_commissions',
                    userId
                )
            ),

            readDocuments(categoriesQuery)
        ]);

        const loadedCategories =
            categoriesSnap.docs.map(docSnap => ({
                id: docSnap.id,
                ...docSnap.data()
            }));

        const defaultPinSettings = {
            dashboard: false,
            incomeHistory: false,
            investmentPage: false,
            laporanTransaksi: false,
            laporanKeuangan: false,
            hargaHpp: false
        };

        if (settingsSnap.exists()) {
            const settingsData =
                settingsSnap.data();

            Object.assign(
                state.settings,
                settingsData
            );

            state.settings.pinProtection = {
                ...defaultPinSettings,
                ...(
                    settingsData.pinProtection ||
                    {}
                )
            };
        } else {
            state.settings.pinProtection =
                defaultPinSettings;
        }

        state.settings.categories =
            loadedCategories;

        if (
            userProfile.data?.inflowCategories
        ) {
            state.settings.inflowCategories =
                userProfile.data.inflowCategories;
        }

        if (promotionsSnap.exists()) {
            const promoData =
                promotionsSnap.data();

            state.promotions.perChannel =
                promoData.perChannel || {};

            state.promotions.perModel =
                promoData.perModel || {};
        } else {
            state.promotions.perChannel = {};
            state.promotions.perModel = {};
        }

        if (commissionsSnap.exists()) {
            const commsData =
                commissionsSnap.data();

            state.commissions.perModel =
                commsData.perModel || {};
        } else {
            state.commissions.perModel = {};
        }

        dataFetched.settings = true;
    } catch (error) {
        dataFetched.settings = false;

        console.error(
            'Error fetching core data:',
            error
        );
    }
};

// Fungsi khusus untuk data produk, harga, dan alokasi
const fetchProductData = async (
    userId,
    loadMore = false
) => {
    const PRODUCTS_PER_PAGE = 100;

    try {
        if (
            !dataFetched.allProductsLoaded ||
            !dataFetched.pricesAndAllocations
        ) {
            await fetchAllProductData(userId);
        }

        const requestedVisibleCount =
            loadMore
                ? state.inventoryPaginated.length +
                    PRODUCTS_PER_PAGE
                : PRODUCTS_PER_PAGE;

        const visibleCount = Math.min(
            requestedVisibleCount,
            state.produk.length
        );

        // Tombol Muat Lebih Banyak sekarang hanya
        // menampilkan produk berikutnya dari data lokal.
        state.inventoryPaginated =
            state.produk.slice(
                0,
                visibleCount
            );

        uiState.productsLastVisible = null;

        uiState.productsHasMore =
            visibleCount <
            state.produk.length;

        dataFetched.products = true;
    } catch (error) {
        console.error(
            "Error menampilkan produk Inventaris:",
            error
        );

        throw error;
    }
};

const fetchAllProductData = async (userId) => {
    // Gunakan flag baru untuk mencegah fetch ulang jika SEMUA data sudah ada
    if (
    dataFetched.allProductsLoaded &&
    dataFetched.pricesAndAllocations
) {
        console.log(
            '[CACHE SESSION] Seluruh produk, harga, dan stok sudah tersedia.'
        );
        return;
    }

    try {
        // Selalu kosongkan array produk, karena fungsi ini bertujuan memuat semuanya dari awal
        state.produk = []; 

        let lastVisible = null;
        let hasMoreData = true;

        // Ambil juga data harga dan alokasi sekali jalan
        const [pricesSnap, allocationsSnap] = await Promise.all([
            getDocs(query(collection(db, 'product_prices'), where("userId", "==", userId))),
            getDocs(query(collection(db, 'stock_allocations'), where("userId", "==", userId))),
        ]);
        const allPrices = pricesSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        const allAllocations = allocationsSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
 // Simpan harga dan alokasi yang sudah berhasil diambil
state.productPrices = allPrices;
state.stockAllocations = allAllocations;

dataFetched.pricesAndAllocations = true;       
        while (hasMoreData) {
            let q = query(
                collection(db, "products"),
                where("userId", "==", userId),
                orderBy("product_name", "asc"),
                limit(500) // Ambil lebih banyak per batch untuk efisiensi
            );

            if (lastVisible) {
                q = query(q, startAfter(lastVisible));
            }

            const productSnap = await getDocs(q);

            if (!productSnap.empty) {
                lastVisible = productSnap.docs[productSnap.docs.length - 1];
                
                // Proses dan langsung tambahkan ke state.produk
                productSnap.forEach(docSnap => {
                    const p = { id: docSnap.id, ...docSnap.data() };
                    const hargaJual = {};
                    const stokAlokasi = {};
                    const productAllocation = allAllocations.find(alloc => alloc.id === p.id);
                    
                    (state.settings.marketplaces || []).forEach(mp => {
                        const priceInfo = allPrices.find(pr => pr.product_id === p.id && pr.marketplace_id === mp.id);
                        hargaJual[mp.id] = priceInfo ? priceInfo.price : 0;
                        stokAlokasi[mp.id] = productAllocation ? (productAllocation[mp.id] || 0) : 0;
                    });

                    state.produk.push({
                        docId: p.id,
                        sku: p.sku,
                        nama: p.product_name,
                        model_id: p.model_id,
                        warna: p.color,
                        varian: p.variant,
                        stokFisik: p.physical_stock,
                        hpp: p.hpp,
                        hargaJual,
                        stokAlokasi,
                        userId: p.userId
                    });
                });
            }

            if (productSnap.docs.length < 500) {
                hasMoreData = false;
            }
        }
        
        // ========================================================
// AMBIL JUGA HARGA LAMA BERDASARKAN PRODUCT_ID
// ========================================================
// Sebagian dokumen harga akun lama belum memiliki userId.
const legacyPrices = await getDocsByProductIds(
    "product_prices",
    state.produk.map(
        product => product.docId
    ),
    userId,
    false
);

// Gabungkan harga dengan userId dan harga format lama.
const mergedPrices = dedupeRowsByDocId([
    ...allPrices,
    ...legacyPrices
]);

state.productPrices = mergedPrices;

// Map membuat pencarian harga jauh lebih cepat
// untuk akun yang produknya banyak.
const priceMap = new Map();

mergedPrices.forEach(price => {
    if (
        !price.product_id ||
        !price.marketplace_id
    ) {
        return;
    }

    priceMap.set(
        `${price.product_id}__${price.marketplace_id}`,
        price.price
    );
});

// Masukkan kembali harga ke masing-masing produk.
state.produk.forEach(product => {
    (
        state.settings.marketplaces ||
        []
    ).forEach(marketplace => {
        const priceKey =
            `${product.docId}__${marketplace.id}`;

        product.hargaJual[marketplace.id] =
            priceMap.has(priceKey)
                ? priceMap.get(priceKey)
                : 0;
    });
});

// Siapkan tampilan awal Inventaris.
// Kalau sebelumnya sudah membuka lebih dari 100,
// pertahankan jumlah yang terlihat.
const visibleCount = Math.min(
    Math.max(
        state.inventoryPaginated.length,
        100
    ),
    state.produk.length
);

state.inventoryPaginated =
    state.produk.slice(
        0,
        visibleCount
    );

uiState.productsLastVisible = null;

uiState.productsHasMore =
    visibleCount <
    state.produk.length;

// Tandai semua data produk berhasil dimuat.
dataFetched.products = true;
dataFetched.allProductsLoaded = true;
dataFetched.pricesAndAllocations = true;

console.log(
    `Successfully fetched ${state.produk.length} total products and ${mergedPrices.length} product prices.`
);

    } catch (error) {
        console.error("Error fetching all products:", error);
    }
};

const fetchTransactionAndReturnData = async (
    userId,
    loadMore = false,
    startDate = null,
    endDate = null,
    forceAll = false
) => {
    const ITEMS_PER_PAGE = 15;

    // Seluruh transaksi dan retur sudah tersedia di state.
    // Jangan unduh ulang saat pindah halaman.
    const fullTransactionDataReady =
        dataFetched.allTransactionsLoaded === true &&
        dataFetched.allReturnsLoaded === true;

    if (
        !loadMore &&
        !startDate &&
        !endDate &&
        fullTransactionDataReady
    ) {
        console.log(
            '[CACHE SESSION] Seluruh transaksi dan retur sudah tersedia.'
        );
        return;
    }

    // --- TRANSAKSI ---
    if (loadMore && !uiState.transaksiHasMore && !startDate && !forceAll) return;

    try {
        let q_trx;

        if (startDate && endDate && !forceAll) {
            q_trx = query(
                collection(db, "transactions"),
                where("userId", "==", userId),
                where("tanggal", ">=", startDate),
                where("tanggal", "<=", endDate),
                orderBy("tanggal", "desc")
            );

            state.transaksi = [];
        } else {
            if (forceAll) {
                q_trx = query(
                    collection(db, "transactions"),
                    where("userId", "==", userId),
                    orderBy("tanggal", "desc")
                );
            } else {
                q_trx = query(
                    collection(db, "transactions"),
                    where("userId", "==", userId),
                    orderBy("tanggal", "desc"),
                    limit(ITEMS_PER_PAGE)
                );

                if (loadMore && uiState.transaksiLastVisible) {
                    q_trx = query(q_trx, startAfter(uiState.transaksiLastVisible));
                }
            }

            if (!loadMore) {
                state.transaksi = [];
                uiState.transaksiHasMore = true;
            }
        }

        const transactionSnap = await getDocs(q_trx);

        if (!transactionSnap.empty) {
            uiState.transaksiLastVisible = transactionSnap.docs[transactionSnap.docs.length - 1];

            transactionSnap.forEach(docSnap => {
    const data = docSnap.data();

    const normalizedTransaction = {
        id: docSnap.id,
        ...data,
        tanggal: data.tanggal?.toDate ? data.tanggal.toDate() : data.tanggal,
        tanggalPencairan: data.tanggalPencairan?.toDate ? data.tanggalPencairan.toDate() : data.tanggalPencairan
    };

    // Jangan tampilkan transaksi yang sudah dihapus / diarsipkan.
    if (!isActiveExportRecord(normalizedTransaction)) return;

    state.transaksi.push(normalizedTransaction);
});
        }

        if (forceAll) {
    uiState.transaksiHasMore = false;

    // Seluruh transaksi user sudah dimuat.
    dataFetched.allTransactionsLoaded = true;
} else if (
    !startDate &&
    transactionSnap.docs.length < ITEMS_PER_PAGE
) {
    uiState.transaksiHasMore = false;
}

        dataFetched.transactions = true;
    } catch (error) {
        console.error("Error fetching transaction data:", error);
    }

    // --- RETUR ---
    if (loadMore && !uiState.returHasMore && !forceAll) return;

    try {
        let q_retur;

        if (forceAll) {
            q_retur = query(
                collection(db, "returns"),
                where("userId", "==", userId),
                orderBy("tanggal", "desc")
            );
        } else {
            q_retur = query(
                collection(db, "returns"),
                where("userId", "==", userId),
                orderBy("tanggal", "desc"),
                limit(ITEMS_PER_PAGE)
            );

            if (loadMore && uiState.returLastVisible) {
                q_retur = query(q_retur, startAfter(uiState.returLastVisible));
            }
        }

        if (!loadMore) {
            state.retur = [];
            uiState.returHasMore = true;
        }

        const returnSnap = await getDocs(q_retur);

        if (!returnSnap.empty) {
            uiState.returLastVisible = returnSnap.docs[returnSnap.docs.length - 1];

            returnSnap.forEach(docSnap => {
                const data = docSnap.data();

                state.retur.push({
                    id: docSnap.id,
                    ...data,
                    tanggal: data.tanggal?.toDate ? data.tanggal.toDate() : data.tanggal
                });
            });
        }

        if (forceAll) {
    uiState.returHasMore = false;

    // Seluruh data retur user sudah dimuat.
    dataFetched.allReturnsLoaded = true;
} else if (
    returnSnap.docs.length < ITEMS_PER_PAGE
) {
    uiState.returHasMore = false;
}

        dataFetched.returns = true;
    } catch (error) {
        console.error("Error fetching return data:", error);
    }
};

