    } else {
        confirmMsg = `Sistem mendeteksi ${uniqueIds.length} ID. Lanjutkan proses?`;
    }

    if (!confirm(confirmMsg)) return;

    isSaving.value = true;

    let countSuccess = 0;
let countReturnCreated = 0;
const notFoundIds = [];
const newReturnDocs = [];

// Menyimpan perubahan transaksi.
// Baru diterapkan ke tampilan setelah batch Firebase berhasil.
const updatedTransactions = [];

// Gabungan stok dari seluruh ID pesanan yang diretur
const returnedStockMap = new Map();

    try {
        const batch = writeBatch(db);

        uniqueIds.forEach(orderId => {
            const foundTrx = state.pendingSettlements.find(t => {
    return (t.marketplaceOrderId || '')
        .toString()
        .trim()
        .toLowerCase() === orderId
        .trim()
        .toLowerCase();
});

            if (!foundTrx) {
                notFoundIds.push(orderId);
                return;
            }

            if (foundTrx.statusPencairan === targetStatus) {
    return;
}

// Simpan status sebelum diubah menjadi Retur/Pengembalian
const previousSettlementStatus =
    foundTrx.statusPencairan || 'Belum Cair';

const trxRef = doc(
    db,
    "transactions",
    foundTrx.id
);

            const updatePayload = {
    statusPencairan: targetStatus
};

if (targetStatus === 'Sudah Cair') {
    updatePayload.tanggalPencairan =
        new Date();
}

batch.update(
    trxRef,
    updatePayload
);

// Simpan perubahan sementara.
// Jangan ubah tampilan sebelum batch berhasil.
updatedTransactions.push({
    id: foundTrx.id,
    updatePayload
});

countSuccess++;

            if (targetStatus === 'Retur/Pengembalian') {
    const returnRef = doc(
        collection(db, "returns")
    );

    // Seluruh item pesanan otomatis diretur.
    // Rumusnya sama dengan Manajemen Retur.
    const returnItems =
        buildReturnItemsFromTransaction(
            foundTrx,
            foundTrx.items || [],
            'Retur / Pengembalian dari Audit & Pencairan Dana'
        );

    if (returnItems.length === 0) {
        throw new Error(
            `Pesanan ${orderId} tidak mempunyai item retur yang valid.`
        );
    }

    const returnData = {
        tanggal: new Date(),
        channelId: foundTrx.channelId || '',
        originalTransactionId: foundTrx.id,
        marketplaceOrderId:
            foundTrx.marketplaceOrderId ||
            orderId,

        sumber: 'Audit & Pencairan Dana',
        statusRetur: 'Retur / Pengembalian',

        // Catatan agar riwayat status tetap jelas
        statusPencairanSebelumRetur:
            previousSettlementStatus,

        items: returnItems,
        userId: currentUser.value.uid,
        createdAt: new Date()
    };

    batch.set(
        returnRef,
        returnData
    );

    // Kumpulkan stok fisik seluruh item pesanan
    addReturnedItemsToStockMap(
        returnedStockMap,
        returnItems
    );

    newReturnDocs.push({
        id: returnRef.id,
        ...returnData
    });

    countReturnCreated++;
}
        });

        if (countSuccess === 0) {
    throw new Error(
        "Tidak ada ID yang cocok dengan daftar pesanan gantung. Periksa kembali ID Pesanan Anda."
    );
}

// Bila prosesnya adalah retur, kembalikan stok fisik.
// Bila Dana Cair atau Batal, Map kosong dan tidak mengubah stok.
queuePhysicalStockReturn(
    batch,
    returnedStockMap
);

await batch.commit();

// Batch Firebase sudah berhasil.
// Sekarang perbarui transaksi pada seluruh state lokal.
updatedTransactions.forEach(
    ({ id, updatePayload }) => {
        const pendingTransaction =
            state.pendingSettlements.find(
                trx => trx.id === id
            );

        if (pendingTransaction) {
            Object.assign(
                pendingTransaction,
                updatePayload
            );
        }

        const mainTransaction =
            state.transaksi.find(
                trx => trx.id === id
            );

        if (mainTransaction) {
            Object.assign(
                mainTransaction,
                updatePayload
            );
        }
    }
);

if (newReturnDocs.length > 0) {
    state.retur.unshift(...newReturnDocs);

    // Perbarui stok yang tampil tanpa harus refresh
    applyPhysicalStockReturnToLocal(
        returnedStockMap
    );
}

        let message = `Berhasil! ${countSuccess} pesanan diperbarui menjadi: ${targetStatus}.`;

        if (countReturnCreated > 0) {
            message += `\n${countReturnCreated} data retur masuk ke Manajemen Retur.`;
        }

        if (notFoundIds.length > 0) {
            message += `\n\nID tidak ditemukan:\n${notFoundIds.slice(0, 10).join('\n')}`;
        }

        alert(message);
        bulkSettlementInput.value = '';

    } catch (error) {
        console.error("Error mass settlement:", error);
        alert(error.message);
    } finally {
        isSaving.value = false;
    }
}

// Fungsi khusus untuk catatan voucher
const fetchNotesData = async (
    userId,
    forceRefresh = false
) => {
    if (
        !forceRefresh &&
        dataFetched.notes
    ) {
        console.log(
            '[CACHE SESSION] Catatan voucher sudah tersedia.'
        );

        return;
    }

    try {
        const readDocuments =
            forceRefresh
                ? getDocsFromServer
                : getDocs;

        const notesSnap =
            await readDocuments(
                query(
                    collection(
                        db,
                        'voucher_notes'
                    ),
                    where(
                        'userId',
                        '==',
                        userId
                    )
                )
            );

        state.voucherNotes =
            notesSnap.docs.map(docSnap => ({
                id: docSnap.id,
                ...docSnap.data(),
                endDate:
                    docSnap
                        .data()
                        .endDate
                        ?.toDate()
            }));

        dataFetched.notes = true;
    } catch (error) {
        dataFetched.notes = false;

        console.error(
            'Error fetching notes data:',
            error
        );
    }
};

function generateUniqueCode() {
    const numbers = Math.floor(10 + Math.random() * 90); // 2 angka acak
    const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 3; i++) {
        result += letters.charAt(Math.floor(Math.random() * letters.length));
    }
    return `${numbers}${result}`;
}

onMounted(() => {
    // Memulai jam reaktif yang akan update setiap 1 menit
    setInterval(() => {
        currentTime.value = new Date();
    }, 60000); 

    onAuthStateChanged(auth, async (user) => {
        isLoading.value = true;
        hasLoadedInitialData.value = false;
        Object.keys(dataFetched).forEach(key => dataFetched[key] = false);

        if (user) {
            currentUser.value = user; // Simpan data otentikasi Firebase

            // Ambil data profil dari Firestore dan simpan di state reaktif terpisah
            const userDocSnap = await getDoc(doc(db, 'users', user.uid));
            userProfile.data = userDocSnap.exists() ? userDocSnap.data() : {};

           await setupListeners(user.uid, userProfile.data.isPartner);

changePage(activePage.value);

// Penting agar data halaman tetap dimuat ketika browser direfresh
await loadDataForPage(activePage.value);

if (userProfile.data.onboardingDone !== true) {
    uiState.onboardingVisible = true;
    uiState.onboardingStep = 0;
}
        } else {
            currentUser.value = null;
            userProfile.data = null; // Kosongkan profil saat logout
            activePage.value = 'login';
            if (unsubscribe) unsubscribe();
        }
        isLoading.value = false;
        hasLoadedInitialData.value = true;
    });
});

watch(activePage, (newPage, oldPage) => {
    localStorage.setItem('lastActivePage', newPage);
    loadDataForPage(newPage);

    // --- LOGIKA BARU UNTUK LISTENER REAL-TIME ---
    if (newPage === 'langganan' && currentUser.value) {
        // Mulai mendengarkan perubahan data pengguna saat masuk ke halaman langganan
        setupUserListener(currentUser.value.uid);
    } else if (oldPage === 'langganan' && userListener) {
        // Hentikan listener saat keluar dari halaman langganan untuk hemat resource
        console.log("Keluar dari halaman langganan, listener dihentikan.");
        userListener();
        userListener = null;
    }
});

</script>

