                                        <button type="button" @click="recordBagiHasilPayment" class="bg-green-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-green-700" :disabled="!isSubscriptionActive">Catat Pembayaran Bagi Hasil</button>
